window.BIBLE = window.BIBLE || {};
window.BIBLE["Job"] = {"1": {"chapter": "1", "title": "Job 1", "verses": {"1": {"text": "There was a man in the land of Uz, whose name was Job; and that man was perfect and upright, and one that feared God, and eschewed evil.", "ref": "Job 1:1"}, "2": {"text": "And there were born unto him seven sons and three daughters.", "ref": "Job 1:2"}, "3": {"text": "His substance also was seven thousand sheep, and three thousand camels, and five hundred yoke of oxen, and five hundred she asses, and a very great household; so that this man was the greatest of all the men of the east.", "ref": "Job 1:3"}, "4": {"text": "And his sons went and feasted in their houses, every one his day; and sent and called for their three sisters to eat and to drink with them.", "ref": "Job 1:4"}, "5": {"text": "And it was so, when the days of their feasting were gone about, that Job sent and sanctified them, and rose up early in the morning, and offered burnt offerings according to the number of them all: for Job said, It may be that my sons have sinned, and cursed God in their hearts. Thus did Job continually.", "ref": "Job 1:5"}, "6": {"text": "Now there was a day when the sons of God came to present themselves before the LORD, and Satan came also among them.", "ref": "Job 1:6"}, "7": {"text": "And the LORD said unto Satan, Whence comest thou? Then Satan answered the LORD, and said, From going to and fro in the earth, and from walking up and down in it.", "ref": "Job 1:7"}, "8": {"text": "And the LORD said unto Satan, Hast thou considered my servant Job, that there is none like him in the earth, a perfect and an upright man, one that feareth God, and escheweth evil?", "ref": "Job 1:8"}, "9": {"text": "Then Satan answered the LORD, and said, Doth Job fear God for nought?", "ref": "Job 1:9"}, "10": {"text": "Hast not thou made an hedge about him, and about his house, and about all that he hath on every side? thou hast blessed the work of his hands, and his substance is increased in the land.", "ref": "Job 1:10"}, "11": {"text": "But put forth thine hand now, and touch all that he hath, and he will curse thee to thy face.", "ref": "Job 1:11"}, "12": {"text": "And the LORD said unto Satan, Behold, all that he hath is in thy power; only upon himself put not forth thine hand. So Satan went forth from the presence of the LORD.", "ref": "Job 1:12"}, "13": {"text": "And there was a day when his sons and his daughters were eating and drinking wine in their eldest brother’s house:", "ref": "Job 1:13"}, "14": {"text": "And there came a messenger unto Job, and said, The oxen were plowing, and the asses feeding beside them:", "ref": "Job 1:14"}, "15": {"text": "And the Sabeans fell upon them, and took them away; yea, they have slain the servants with the edge of the sword; and I only am escaped alone to tell thee.", "ref": "Job 1:15"}, "16": {"text": "While he was yet speaking, there came also another, and said, The fire of God is fallen from heaven, and hath burned up the sheep, and the servants, and consumed them; and I only am escaped alone to tell thee.", "ref": "Job 1:16"}, "17": {"text": "While he was yet speaking, there came also another, and said, The Chaldeans made out three bands, and fell upon the camels, and have carried them away, yea, and slain the servants with the edge of the sword; and I only am escaped alone to tell thee.", "ref": "Job 1:17"}, "18": {"text": "While he was yet speaking, there came also another, and said, Thy sons and thy daughters were eating and drinking wine in their eldest brother’s house:", "ref": "Job 1:18"}, "19": {"text": "And, behold, there came a great wind from the wilderness, and smote the four corners of the house, and it fell upon the young men, and they are dead; and I only am escaped alone to tell thee.", "ref": "Job 1:19"}, "20": {"text": "Then Job arose, and rent his mantle, and shaved his head, and fell down upon the ground, and worshipped,", "ref": "Job 1:20"}, "21": {"text": "And said, Naked came I out of my mother’s womb, and naked shall I return thither: the LORD gave, and the LORD hath taken away; blessed be the name of the LORD.", "ref": "Job 1:21"}, "22": {"text": "In all this Job sinned not, nor charged God foolishly.", "ref": "Job 1:22"}}}, "2": {"chapter": "2", "title": "Job 2", "verses": {"1": {"text": "Again there was a day when the sons of God came to present themselves before the LORD, and Satan came also among them to present himself before the LORD.", "ref": "Job 2:1"}, "2": {"text": "And the LORD said unto Satan, From whence comest thou? And Satan answered the LORD, and said, From going to and fro in the earth, and from walking up and down in it.", "ref": "Job 2:2"}, "3": {"text": "And the LORD said unto Satan, Hast thou considered my servant Job, that there is none like him in the earth, a perfect and an upright man, one that feareth God, and escheweth evil? and still he holdeth fast his integrity, although thou movedst me against him, to destroy him without cause.", "ref": "Job 2:3"}, "4": {"text": "And Satan answered the LORD, and said, Skin for skin, yea, all that a man hath will he give for his life.", "ref": "Job 2:4"}, "5": {"text": "But put forth thine hand now, and touch his bone and his flesh, and he will curse thee to thy face.", "ref": "Job 2:5"}, "6": {"text": "And the LORD said unto Satan, Behold, he is in thine hand; but save his life.", "ref": "Job 2:6"}, "7": {"text": "So went Satan forth from the presence of the LORD, and smote Job with sore boils from the sole of his foot unto his crown.", "ref": "Job 2:7"}, "8": {"text": "And he took him a potsherd to scrape himself withal; and he sat down among the ashes.", "ref": "Job 2:8"}, "9": {"text": "Then said his wife unto him, Dost thou still retain thine integrity? curse God, and die.", "ref": "Job 2:9"}, "10": {"text": "But he said unto her, Thou speakest as one of the foolish women speaketh. What? shall we receive good at the hand of God, and shall we not receive evil? In all this did not Job sin with his lips.", "ref": "Job 2:10"}, "11": {"text": "Now when Job’s three friends heard of all this evil that was come upon him, they came every one from his own place; Eliphaz the Temanite, and Bildad the Shuhite, and Zophar the Naamathite: for they had made an appointment together to come to mourn with him and to comfort him.", "ref": "Job 2:11"}, "12": {"text": "And when they lifted up their eyes afar off, and knew him not, they lifted up their voice, and wept; and they rent every one his mantle, and sprinkled dust upon their heads toward heaven.", "ref": "Job 2:12"}, "13": {"text": "So they sat down with him upon the ground seven days and seven nights, and none spake a word unto him: for they saw that his grief was very great.", "ref": "Job 2:13"}}}, "3": {"chapter": "3", "title": "Job 3", "verses": {"1": {"text": "After this opened Job his mouth, and cursed his day.", "ref": "Job 3:1"}, "2": {"text": "And Job spake, and said,", "ref": "Job 3:2"}, "3": {"text": "Let the day perish wherein I was born, and the night in which it was said, There is a man child conceived.", "ref": "Job 3:3"}, "4": {"text": "Let that day be darkness; let not God regard it from above, neither let the light shine upon it.", "ref": "Job 3:4"}, "5": {"text": "Let darkness and the shadow of death stain it; let a cloud dwell upon it; let the blackness of the day terrify it.", "ref": "Job 3:5"}, "6": {"text": "As for that night, let darkness seize upon it; let it not be joined unto the days of the year, let it not come into the number of the months.", "ref": "Job 3:6"}, "7": {"text": "Lo, let that night be solitary, let no joyful voice come therein.", "ref": "Job 3:7"}, "8": {"text": "Let them curse it that curse the day, who are ready to raise up their mourning.", "ref": "Job 3:8"}, "9": {"text": "Let the stars of the twilight thereof be dark; let it look for light, but have none; neither let it see the dawning of the day:", "ref": "Job 3:9"}, "10": {"text": "Because it shut not up the doors of my mother’s womb, nor hid sorrow from mine eyes.", "ref": "Job 3:10"}, "11": {"text": "Why died I not from the womb? why did I not give up the ghost when I came out of the belly?", "ref": "Job 3:11"}, "12": {"text": "Why did the knees prevent me? or why the breasts that I should suck?", "ref": "Job 3:12"}, "13": {"text": "For now should I have lain still and been quiet, I should have slept: then had I been at rest,", "ref": "Job 3:13"}, "14": {"text": "With kings and counsellors of the earth, which built desolate places for themselves;", "ref": "Job 3:14"}, "15": {"text": "Or with princes that had gold, who filled their houses with silver:", "ref": "Job 3:15"}, "16": {"text": "Or as an hidden untimely birth I had not been; as infants which never saw light.", "ref": "Job 3:16"}, "17": {"text": "There the wicked cease from troubling; and there the weary be at rest.", "ref": "Job 3:17"}, "18": {"text": "There the prisoners rest together; they hear not the voice of the oppressor.", "ref": "Job 3:18"}, "19": {"text": "The small and great are there; and the servant is free from his master.", "ref": "Job 3:19"}, "20": {"text": "Wherefore is light given to him that is in misery, and life unto the bitter in soul;", "ref": "Job 3:20"}, "21": {"text": "Which long for death, but it cometh not; and dig for it more than for hid treasures;", "ref": "Job 3:21"}, "22": {"text": "Which rejoice exceedingly, and are glad, when they can find the grave?", "ref": "Job 3:22"}, "23": {"text": "Why is light given to a man whose way is hid, and whom God hath hedged in?", "ref": "Job 3:23"}, "24": {"text": "For my sighing cometh before I eat, and my roarings are poured out like the waters.", "ref": "Job 3:24"}, "25": {"text": "For the thing which I greatly feared is come upon me, and that which I was afraid of is come unto me.", "ref": "Job 3:25"}, "26": {"text": "I was not in safety, neither had I rest, neither was I quiet; yet trouble came.", "ref": "Job 3:26"}}}, "4": {"chapter": "4", "title": "Job 4", "verses": {"1": {"text": "Then Eliphaz the Temanite answered and said,", "ref": "Job 4:1"}, "2": {"text": "If we assay to commune with thee, wilt thou be grieved? but who can withhold himself from speaking?", "ref": "Job 4:2"}, "3": {"text": "Behold, thou hast instructed many, and thou hast strengthened the weak hands.", "ref": "Job 4:3"}, "4": {"text": "Thy words have upholden him that was falling, and thou hast strengthened the feeble knees.", "ref": "Job 4:4"}, "5": {"text": "But now it is come upon thee, and thou faintest; it toucheth thee, and thou art troubled.", "ref": "Job 4:5"}, "6": {"text": "Is not this thy fear, thy confidence, thy hope, and the uprightness of thy ways?", "ref": "Job 4:6"}, "7": {"text": "Remember, I pray thee, who ever perished, being innocent? or where were the righteous cut off?", "ref": "Job 4:7"}, "8": {"text": "Even as I have seen, they that plow iniquity, and sow wickedness, reap the same.", "ref": "Job 4:8"}, "9": {"text": "By the blast of God they perish, and by the breath of his nostrils are they consumed.", "ref": "Job 4:9"}, "10": {"text": "The roaring of the lion, and the voice of the fierce lion, and the teeth of the young lions, are broken.", "ref": "Job 4:10"}, "11": {"text": "The old lion perisheth for lack of prey, and the stout lion’s whelps are scattered abroad.", "ref": "Job 4:11"}, "12": {"text": "Now a thing was secretly brought to me, and mine ear received a little thereof.", "ref": "Job 4:12"}, "13": {"text": "In thoughts from the visions of the night, when deep sleep falleth on men,", "ref": "Job 4:13"}, "14": {"text": "Fear came upon me, and trembling, which made all my bones to shake.", "ref": "Job 4:14"}, "15": {"text": "Then a spirit passed before my face; the hair of my flesh stood up:", "ref": "Job 4:15"}, "16": {"text": "It stood still, but I could not discern the form thereof: an image was before mine eyes, there was silence, and I heard a voice, saying,", "ref": "Job 4:16"}, "17": {"text": "Shall mortal man be more just than God? shall a man be more pure than his maker?", "ref": "Job 4:17"}, "18": {"text": "Behold, he put no trust in his servants; and his angels he charged with folly:", "ref": "Job 4:18"}, "19": {"text": "How much less in them that dwell in houses of clay, whose foundation is in the dust, which are crushed before the moth?", "ref": "Job 4:19"}, "20": {"text": "They are destroyed from morning to evening: they perish for ever without any regarding it.", "ref": "Job 4:20"}, "21": {"text": "Doth not their excellency which is in them go away? they die, even without wisdom.", "ref": "Job 4:21"}}}, "5": {"chapter": "5", "title": "Job 5", "verses": {"1": {"text": "Call now, if there be any that will answer thee; and to which of the saints wilt thou turn?", "ref": "Job 5:1"}, "2": {"text": "For wrath killeth the foolish man, and envy slayeth the silly one.", "ref": "Job 5:2"}, "3": {"text": "I have seen the foolish taking root: but suddenly I cursed his habitation.", "ref": "Job 5:3"}, "4": {"text": "His children are far from safety, and they are crushed in the gate, neither is there any to deliver them.", "ref": "Job 5:4"}, "5": {"text": "Whose harvest the hungry eateth up, and taketh it even out of the thorns, and the robber swalloweth up their substance.", "ref": "Job 5:5"}, "6": {"text": "Although affliction cometh not forth of the dust, neither doth trouble spring out of the ground;", "ref": "Job 5:6"}, "7": {"text": "Yet man is born unto trouble, as the sparks fly upward.", "ref": "Job 5:7"}, "8": {"text": "I would seek unto God, and unto God would I commit my cause:", "ref": "Job 5:8"}, "9": {"text": "Which doeth great things and unsearchable; marvellous things without number:", "ref": "Job 5:9"}, "10": {"text": "Who giveth rain upon the earth, and sendeth waters upon the fields:", "ref": "Job 5:10"}, "11": {"text": "To set up on high those that be low; that those which mourn may be exalted to safety.", "ref": "Job 5:11"}, "12": {"text": "He disappointeth the devices of the crafty, so that their hands cannot perform their enterprise.", "ref": "Job 5:12"}, "13": {"text": "He taketh the wise in their own craftiness: and the counsel of the froward is carried headlong.", "ref": "Job 5:13"}, "14": {"text": "They meet with darkness in the day time, and grope in the noonday as in the night.", "ref": "Job 5:14"}, "15": {"text": "But he saveth the poor from the sword, from their mouth, and from the hand of the mighty.", "ref": "Job 5:15"}, "16": {"text": "So the poor hath hope, and iniquity stoppeth her mouth.", "ref": "Job 5:16"}, "17": {"text": "Behold, happy is the man whom God correcteth: therefore despise not thou the chastening of the Almighty:", "ref": "Job 5:17"}, "18": {"text": "For he maketh sore, and bindeth up: he woundeth, and his hands make whole.", "ref": "Job 5:18"}, "19": {"text": "He shall deliver thee in six troubles: yea, in seven there shall no evil touch thee.", "ref": "Job 5:19"}, "20": {"text": "In famine he shall redeem thee from death: and in war from the power of the sword.", "ref": "Job 5:20"}, "21": {"text": "Thou shalt be hid from the scourge of the tongue: neither shalt thou be afraid of destruction when it cometh.", "ref": "Job 5:21"}, "22": {"text": "At destruction and famine thou shalt laugh: neither shalt thou be afraid of the beasts of the earth.", "ref": "Job 5:22"}, "23": {"text": "For thou shalt be in league with the stones of the field: and the beasts of the field shall be at peace with thee.", "ref": "Job 5:23"}, "24": {"text": "And thou shalt know that thy tabernacle shall be in peace; and thou shalt visit thy habitation, and shalt not sin.", "ref": "Job 5:24"}, "25": {"text": "Thou shalt know also that thy seed shall be great, and thine offspring as the grass of the earth.", "ref": "Job 5:25"}, "26": {"text": "Thou shalt come to thy grave in a full age, like as a shock of corn cometh in in his season.", "ref": "Job 5:26"}, "27": {"text": "Lo this, we have searched it, so it is; hear it, and know thou it for thy good.", "ref": "Job 5:27"}}}, "6": {"chapter": "6", "title": "Job 6", "verses": {"1": {"text": "But Job answered and said,", "ref": "Job 6:1"}, "2": {"text": "Oh that my grief were throughly weighed, and my calamity laid in the balances together!", "ref": "Job 6:2"}, "3": {"text": "For now it would be heavier than the sand of the sea: therefore my words are swallowed up.", "ref": "Job 6:3"}, "4": {"text": "For the arrows of the Almighty are within me, the poison whereof drinketh up my spirit: the terrors of God do set themselves in array against me.", "ref": "Job 6:4"}, "5": {"text": "Doth the wild ass bray when he hath grass? or loweth the ox over his fodder?", "ref": "Job 6:5"}, "6": {"text": "Can that which is unsavoury be eaten without salt? or is there any taste in the white of an egg?", "ref": "Job 6:6"}, "7": {"text": "The things that my soul refused to touch are as my sorrowful meat.", "ref": "Job 6:7"}, "8": {"text": "Oh that I might have my request; and that God would grant me the thing that I long for!", "ref": "Job 6:8"}, "9": {"text": "Even that it would please God to destroy me; that he would let loose his hand, and cut me off!", "ref": "Job 6:9"}, "10": {"text": "Then should I yet have comfort; yea, I would harden myself in sorrow: let him not spare; for I have not concealed the words of the Holy One.", "ref": "Job 6:10"}, "11": {"text": "What is my strength, that I should hope? and what is mine end, that I should prolong my life?", "ref": "Job 6:11"}, "12": {"text": "Is my strength the strength of stones? or is my flesh of brass?", "ref": "Job 6:12"}, "13": {"text": "Is not my help in me? and is wisdom driven quite from me?", "ref": "Job 6:13"}, "14": {"text": "To him that is afflicted pity should be shewed from his friend; but he forsaketh the fear of the Almighty.", "ref": "Job 6:14"}, "15": {"text": "My brethren have dealt deceitfully as a brook, and as the stream of brooks they pass away;", "ref": "Job 6:15"}, "16": {"text": "Which are blackish by reason of the ice, and wherein the snow is hid:", "ref": "Job 6:16"}, "17": {"text": "What time they wax warm, they vanish: when it is hot, they are consumed out of their place.", "ref": "Job 6:17"}, "18": {"text": "The paths of their way are turned aside; they go to nothing, and perish.", "ref": "Job 6:18"}, "19": {"text": "The troops of Tema looked, the companies of Sheba waited for them.", "ref": "Job 6:19"}, "20": {"text": "They were confounded because they had hoped; they came thither, and were ashamed.", "ref": "Job 6:20"}, "21": {"text": "For now ye are nothing; ye see my casting down, and are afraid.", "ref": "Job 6:21"}, "22": {"text": "Did I say, Bring unto me? or, Give a reward for me of your substance?", "ref": "Job 6:22"}, "23": {"text": "Or, Deliver me from the enemy’s hand? or, Redeem me from the hand of the mighty?", "ref": "Job 6:23"}, "24": {"text": "Teach me, and I will hold my tongue: and cause me to understand wherein I have erred.", "ref": "Job 6:24"}, "25": {"text": "How forcible are right words! but what doth your arguing reprove?", "ref": "Job 6:25"}, "26": {"text": "Do ye imagine to reprove words, and the speeches of one that is desperate, which are as wind?", "ref": "Job 6:26"}, "27": {"text": "Yea, ye overwhelm the fatherless, and ye dig a pit for your friend.", "ref": "Job 6:27"}, "28": {"text": "Now therefore be content, look upon me; for it is evident unto you if I lie.", "ref": "Job 6:28"}, "29": {"text": "Return, I pray you, let it not be iniquity; yea, return again, my righteousness is in it.", "ref": "Job 6:29"}, "30": {"text": "Is there iniquity in my tongue? cannot my taste discern perverse things?", "ref": "Job 6:30"}}}, "7": {"chapter": "7", "title": "Job 7", "verses": {"1": {"text": "Is there not an appointed time to man upon earth? are not his days also like the days of an hireling?", "ref": "Job 7:1"}, "2": {"text": "As a servant earnestly desireth the shadow, and as an hireling looketh for the reward of his work:", "ref": "Job 7:2"}, "3": {"text": "So am I made to possess months of vanity, and wearisome nights are appointed to me.", "ref": "Job 7:3"}, "4": {"text": "When I lie down, I say, When shall I arise, and the night be gone? and I am full of tossings to and fro unto the dawning of the day.", "ref": "Job 7:4"}, "5": {"text": "My flesh is clothed with worms and clods of dust; my skin is broken, and become loathsome.", "ref": "Job 7:5"}, "6": {"text": "My days are swifter than a weaver’s shuttle, and are spent without hope.", "ref": "Job 7:6"}, "7": {"text": "O remember that my life is wind: mine eye shall no more see good.", "ref": "Job 7:7"}, "8": {"text": "The eye of him that hath seen me shall see me no more: thine eyes are upon me, and I am not.", "ref": "Job 7:8"}, "9": {"text": "As the cloud is consumed and vanisheth away: so he that goeth down to the grave shall come up no more.", "ref": "Job 7:9"}, "10": {"text": "He shall return no more to his house, neither shall his place know him any more.", "ref": "Job 7:10"}, "11": {"text": "Therefore I will not refrain my mouth; I will speak in the anguish of my spirit; I will complain in the bitterness of my soul.", "ref": "Job 7:11"}, "12": {"text": "Am I a sea, or a whale, that thou settest a watch over me?", "ref": "Job 7:12"}, "13": {"text": "When I say, My bed shall comfort me, my couch shall ease my complaint;", "ref": "Job 7:13"}, "14": {"text": "Then thou scarest me with dreams, and terrifiest me through visions:", "ref": "Job 7:14"}, "15": {"text": "So that my soul chooseth strangling, and death rather than my life.", "ref": "Job 7:15"}, "16": {"text": "I loathe it; I would not live alway: let me alone; for my days are vanity.", "ref": "Job 7:16"}, "17": {"text": "What is man, that thou shouldest magnify him? and that thou shouldest set thine heart upon him?", "ref": "Job 7:17"}, "18": {"text": "And that thou shouldest visit him every morning, and try him every moment?", "ref": "Job 7:18"}, "19": {"text": "How long wilt thou not depart from me, nor let me alone till I swallow down my spittle?", "ref": "Job 7:19"}, "20": {"text": "I have sinned; what shall I do unto thee, O thou preserver of men? why hast thou set me as a mark against thee, so that I am a burden to myself?", "ref": "Job 7:20"}, "21": {"text": "And why dost thou not pardon my transgression, and take away mine iniquity? for now shall I sleep in the dust; and thou shalt seek me in the morning, but I shall not be.", "ref": "Job 7:21"}}}, "8": {"chapter": "8", "title": "Job 8", "verses": {"1": {"text": "Then answered Bildad the Shuhite, and said,", "ref": "Job 8:1"}, "2": {"text": "How long wilt thou speak these things? and how long shall the words of thy mouth be like a strong wind?", "ref": "Job 8:2"}, "3": {"text": "Doth God pervert judgment? or doth the Almighty pervert justice?", "ref": "Job 8:3"}, "4": {"text": "If thy children have sinned against him, and he have cast them away for their transgression;", "ref": "Job 8:4"}, "5": {"text": "If thou wouldest seek unto God betimes, and make thy supplication to the Almighty;", "ref": "Job 8:5"}, "6": {"text": "If thou wert pure and upright; surely now he would awake for thee, and make the habitation of thy righteousness prosperous.", "ref": "Job 8:6"}, "7": {"text": "Though thy beginning was small, yet thy latter end should greatly increase.", "ref": "Job 8:7"}, "8": {"text": "For enquire, I pray thee, of the former age, and prepare thyself to the search of their fathers:", "ref": "Job 8:8"}, "9": {"text": "(For we are but of yesterday, and know nothing, because our days upon earth are a shadow:)", "ref": "Job 8:9"}, "10": {"text": "Shall not they teach thee, and tell thee, and utter words out of their heart?", "ref": "Job 8:10"}, "11": {"text": "Can the rush grow up without mire? can the flag grow without water?", "ref": "Job 8:11"}, "12": {"text": "Whilst it is yet in his greenness, and not cut down, it withereth before any other herb.", "ref": "Job 8:12"}, "13": {"text": "So are the paths of all that forget God; and the hypocrite’s hope shall perish:", "ref": "Job 8:13"}, "14": {"text": "Whose hope shall be cut off, and whose trust shall be a spider’s web.", "ref": "Job 8:14"}, "15": {"text": "He shall lean upon his house, but it shall not stand: he shall hold it fast, but it shall not endure.", "ref": "Job 8:15"}, "16": {"text": "He is green before the sun, and his branch shooteth forth in his garden.", "ref": "Job 8:16"}, "17": {"text": "His roots are wrapped about the heap, and seeth the place of stones.", "ref": "Job 8:17"}, "18": {"text": "If he destroy him from his place, then it shall deny him, saying, I have not seen thee.", "ref": "Job 8:18"}, "19": {"text": "Behold, this is the joy of his way, and out of the earth shall others grow.", "ref": "Job 8:19"}, "20": {"text": "Behold, God will not cast away a perfect man, neither will he help the evil doers:", "ref": "Job 8:20"}, "21": {"text": "Till he fill thy mouth with laughing, and thy lips with rejoicing.", "ref": "Job 8:21"}, "22": {"text": "They that hate thee shall be clothed with shame; and the dwelling place of the wicked shall come to nought.", "ref": "Job 8:22"}}}, "9": {"chapter": "9", "title": "Job 9", "verses": {"1": {"text": "Then Job answered and said,", "ref": "Job 9:1"}, "2": {"text": "I know it is so of a truth: but how should man be just with God?", "ref": "Job 9:2"}, "3": {"text": "If he will contend with him, he cannot answer him one of a thousand.", "ref": "Job 9:3"}, "4": {"text": "He is wise in heart, and mighty in strength: who hath hardened himself against him, and hath prospered?", "ref": "Job 9:4"}, "5": {"text": "Which removeth the mountains, and they know not: which overturneth them in his anger.", "ref": "Job 9:5"}, "6": {"text": "Which shaketh the earth out of her place, and the pillars thereof tremble.", "ref": "Job 9:6"}, "7": {"text": "Which commandeth the sun, and it riseth not; and sealeth up the stars.", "ref": "Job 9:7"}, "8": {"text": "Which alone spreadeth out the heavens, and treadeth upon the waves of the sea.", "ref": "Job 9:8"}, "9": {"text": "Which maketh Arcturus, Orion, and Pleiades, and the chambers of the south.", "ref": "Job 9:9"}, "10": {"text": "Which doeth great things past finding out; yea, and wonders without number.", "ref": "Job 9:10"}, "11": {"text": "Lo, he goeth by me, and I see him not: he passeth on also, but I perceive him not.", "ref": "Job 9:11"}, "12": {"text": "Behold, he taketh away, who can hinder him? who will say unto him, What doest thou?", "ref": "Job 9:12"}, "13": {"text": "If God will not withdraw his anger, the proud helpers do stoop under him.", "ref": "Job 9:13"}, "14": {"text": "How much less shall I answer him, and choose out my words to reason with him?", "ref": "Job 9:14"}, "15": {"text": "Whom, though I were righteous, yet would I not answer, but I would make supplication to my judge.", "ref": "Job 9:15"}, "16": {"text": "If I had called, and he had answered me; yet would I not believe that he had hearkened unto my voice.", "ref": "Job 9:16"}, "17": {"text": "For he breaketh me with a tempest, and multiplieth my wounds without cause.", "ref": "Job 9:17"}, "18": {"text": "He will not suffer me to take my breath, but filleth me with bitterness.", "ref": "Job 9:18"}, "19": {"text": "If I speak of strength, lo, he is strong: and if of judgment, who shall set me a time to plead?", "ref": "Job 9:19"}, "20": {"text": "If I justify myself, mine own mouth shall condemn me: if I say, I am perfect, it shall also prove me perverse.", "ref": "Job 9:20"}, "21": {"text": "Though I were perfect, yet would I not know my soul: I would despise my life.", "ref": "Job 9:21"}, "22": {"text": "This is one thing, therefore I said it, He destroyeth the perfect and the wicked.", "ref": "Job 9:22"}, "23": {"text": "If the scourge slay suddenly, he will laugh at the trial of the innocent.", "ref": "Job 9:23"}, "24": {"text": "The earth is given into the hand of the wicked: he covereth the faces of the judges thereof; if not, where, and who is he?", "ref": "Job 9:24"}, "25": {"text": "Now my days are swifter than a post: they flee away, they see no good.", "ref": "Job 9:25"}, "26": {"text": "They are passed away as the swift ships: as the eagle that hasteth to the prey.", "ref": "Job 9:26"}, "27": {"text": "If I say, I will forget my complaint, I will leave off my heaviness, and comfort myself:", "ref": "Job 9:27"}, "28": {"text": "I am afraid of all my sorrows, I know that thou wilt not hold me innocent.", "ref": "Job 9:28"}, "29": {"text": "If I be wicked, why then labour I in vain?", "ref": "Job 9:29"}, "30": {"text": "If I wash myself with snow water, and make my hands never so clean;", "ref": "Job 9:30"}, "31": {"text": "Yet shalt thou plunge me in the ditch, and mine own clothes shall abhor me.", "ref": "Job 9:31"}, "32": {"text": "For he is not a man, as I am, that I should answer him, and we should come together in judgment.", "ref": "Job 9:32"}, "33": {"text": "Neither is there any daysman betwixt us, that might lay his hand upon us both.", "ref": "Job 9:33"}, "34": {"text": "Let him take his rod away from me, and let not his fear terrify me:", "ref": "Job 9:34"}, "35": {"text": "Then would I speak, and not fear him; but it is not so with me.", "ref": "Job 9:35"}}}, "10": {"chapter": "10", "title": "Job 10", "verses": {"1": {"text": "My soul is weary of my life; I will leave my complaint upon myself; I will speak in the bitterness of my soul.", "ref": "Job 10:1"}, "2": {"text": "I will say unto God, Do not condemn me; shew me wherefore thou contendest with me.", "ref": "Job 10:2"}, "3": {"text": "Is it good unto thee that thou shouldest oppress, that thou shouldest despise the work of thine hands, and shine upon the counsel of the wicked?", "ref": "Job 10:3"}, "4": {"text": "Hast thou eyes of flesh? or seest thou as man seeth?", "ref": "Job 10:4"}, "5": {"text": "Are thy days as the days of man? are thy years as man’s days,", "ref": "Job 10:5"}, "6": {"text": "That thou enquirest after mine iniquity, and searchest after my sin?", "ref": "Job 10:6"}, "7": {"text": "Thou knowest that I am not wicked; and there is none that can deliver out of thine hand.", "ref": "Job 10:7"}, "8": {"text": "Thine hands have made me and fashioned me together round about; yet thou dost destroy me.", "ref": "Job 10:8"}, "9": {"text": "Remember, I beseech thee, that thou hast made me as the clay; and wilt thou bring me into dust again?", "ref": "Job 10:9"}, "10": {"text": "Hast thou not poured me out as milk, and curdled me like cheese?", "ref": "Job 10:10"}, "11": {"text": "Thou hast clothed me with skin and flesh, and hast fenced me with bones and sinews.", "ref": "Job 10:11"}, "12": {"text": "Thou hast granted me life and favour, and thy visitation hath preserved my spirit.", "ref": "Job 10:12"}, "13": {"text": "And these things hast thou hid in thine heart: I know that this is with thee.", "ref": "Job 10:13"}, "14": {"text": "If I sin, then thou markest me, and thou wilt not acquit me from mine iniquity.", "ref": "Job 10:14"}, "15": {"text": "If I be wicked, woe unto me; and if I be righteous, yet will I not lift up my head. I am full of confusion; therefore see thou mine affliction;", "ref": "Job 10:15"}, "16": {"text": "For it increaseth. Thou huntest me as a fierce lion: and again thou shewest thyself marvellous upon me.", "ref": "Job 10:16"}, "17": {"text": "Thou renewest thy witnesses against me, and increasest thine indignation upon me; changes and war are against me.", "ref": "Job 10:17"}, "18": {"text": "Wherefore then hast thou brought me forth out of the womb? Oh that I had given up the ghost, and no eye had seen me!", "ref": "Job 10:18"}, "19": {"text": "I should have been as though I had not been; I should have been carried from the womb to the grave.", "ref": "Job 10:19"}, "20": {"text": "Are not my days few? cease then, and let me alone, that I may take comfort a little,", "ref": "Job 10:20"}, "21": {"text": "Before I go whence I shall not return, even to the land of darkness and the shadow of death;", "ref": "Job 10:21"}, "22": {"text": "A land of darkness, as darkness itself; and of the shadow of death, without any order, and where the light is as darkness.", "ref": "Job 10:22"}}}, "11": {"chapter": "11", "title": "Job 11", "verses": {"1": {"text": "Then answered Zophar the Naamathite, and said,", "ref": "Job 11:1"}, "2": {"text": "Should not the multitude of words be answered? and should a man full of talk be justified?", "ref": "Job 11:2"}, "3": {"text": "Should thy lies make men hold their peace? and when thou mockest, shall no man make thee ashamed?", "ref": "Job 11:3"}, "4": {"text": "For thou hast said, My doctrine is pure, and I am clean in thine eyes.", "ref": "Job 11:4"}, "5": {"text": "But oh that God would speak, and open his lips against thee;", "ref": "Job 11:5"}, "6": {"text": "And that he would shew thee the secrets of wisdom, that they are double to that which is! Know therefore that God exacteth of thee less than thine iniquity deserveth.", "ref": "Job 11:6"}, "7": {"text": "Canst thou by searching find out God? canst thou find out the Almighty unto perfection?", "ref": "Job 11:7"}, "8": {"text": "It is as high as heaven; what canst thou do? deeper than hell; what canst thou know?", "ref": "Job 11:8"}, "9": {"text": "The measure thereof is longer than the earth, and broader than the sea.", "ref": "Job 11:9"}, "10": {"text": "If he cut off, and shut up, or gather together, then who can hinder him?", "ref": "Job 11:10"}, "11": {"text": "For he knoweth vain men: he seeth wickedness also; will he not then consider it?", "ref": "Job 11:11"}, "12": {"text": "For vain man would be wise, though man be born like a wild ass’s colt.", "ref": "Job 11:12"}, "13": {"text": "If thou prepare thine heart, and stretch out thine hands toward him;", "ref": "Job 11:13"}, "14": {"text": "If iniquity be in thine hand, put it far away, and let not wickedness dwell in thy tabernacles.", "ref": "Job 11:14"}, "15": {"text": "For then shalt thou lift up thy face without spot; yea, thou shalt be stedfast, and shalt not fear:", "ref": "Job 11:15"}, "16": {"text": "Because thou shalt forget thy misery, and remember it as waters that pass away:", "ref": "Job 11:16"}, "17": {"text": "And thine age shall be clearer than the noonday: thou shalt shine forth, thou shalt be as the morning.", "ref": "Job 11:17"}, "18": {"text": "And thou shalt be secure, because there is hope; yea, thou shalt dig about thee, and thou shalt take thy rest in safety.", "ref": "Job 11:18"}, "19": {"text": "Also thou shalt lie down, and none shall make thee afraid; yea, many shall make suit unto thee.", "ref": "Job 11:19"}, "20": {"text": "But the eyes of the wicked shall fail, and they shall not escape, and their hope shall be as the giving up of the ghost.", "ref": "Job 11:20"}}}, "12": {"chapter": "12", "title": "Job 12", "verses": {"1": {"text": "And Job answered and said,", "ref": "Job 12:1"}, "2": {"text": "No doubt but ye are the people, and wisdom shall die with you.", "ref": "Job 12:2"}, "3": {"text": "But I have understanding as well as you; I am not inferior to you: yea, who knoweth not such things as these?", "ref": "Job 12:3"}, "4": {"text": "I am as one mocked of his neighbour, who calleth upon God, and he answereth him: the just upright man is laughed to scorn.", "ref": "Job 12:4"}, "5": {"text": "He that is ready to slip with his feet is as a lamp despised in the thought of him that is at ease.", "ref": "Job 12:5"}, "6": {"text": "The tabernacles of robbers prosper, and they that provoke God are secure; into whose hand God bringeth abundantly.", "ref": "Job 12:6"}, "7": {"text": "But ask now the beasts, and they shall teach thee; and the fowls of the air, and they shall tell thee:", "ref": "Job 12:7"}, "8": {"text": "Or speak to the earth, and it shall teach thee: and the fishes of the sea shall declare unto thee.", "ref": "Job 12:8"}, "9": {"text": "Who knoweth not in all these that the hand of the LORD hath wrought this?", "ref": "Job 12:9"}, "10": {"text": "In whose hand is the soul of every living thing, and the breath of all mankind.", "ref": "Job 12:10"}, "11": {"text": "Doth not the ear try words? and the mouth taste his meat?", "ref": "Job 12:11"}, "12": {"text": "With the ancient is wisdom; and in length of days understanding.", "ref": "Job 12:12"}, "13": {"text": "With him is wisdom and strength, he hath counsel and understanding.", "ref": "Job 12:13"}, "14": {"text": "Behold, he breaketh down, and it cannot be built again: he shutteth up a man, and there can be no opening.", "ref": "Job 12:14"}, "15": {"text": "Behold, he withholdeth the waters, and they dry up: also he sendeth them out, and they overturn the earth.", "ref": "Job 12:15"}, "16": {"text": "With him is strength and wisdom: the deceived and the deceiver are his.", "ref": "Job 12:16"}, "17": {"text": "He leadeth counsellors away spoiled, and maketh the judges fools.", "ref": "Job 12:17"}, "18": {"text": "He looseth the bond of kings, and girdeth their loins with a girdle.", "ref": "Job 12:18"}, "19": {"text": "He leadeth princes away spoiled, and overthroweth the mighty.", "ref": "Job 12:19"}, "20": {"text": "He removeth away the speech of the trusty, and taketh away the understanding of the aged.", "ref": "Job 12:20"}, "21": {"text": "He poureth contempt upon princes, and weakeneth the strength of the mighty.", "ref": "Job 12:21"}, "22": {"text": "He discovereth deep things out of darkness, and bringeth out to light the shadow of death.", "ref": "Job 12:22"}, "23": {"text": "He increaseth the nations, and destroyeth them: he enlargeth the nations, and straiteneth them again.", "ref": "Job 12:23"}, "24": {"text": "He taketh away the heart of the chief of the people of the earth, and causeth them to wander in a wilderness where there is no way.", "ref": "Job 12:24"}, "25": {"text": "They grope in the dark without light, and he maketh them to stagger like a drunken man.", "ref": "Job 12:25"}}}, "13": {"chapter": "13", "title": "Job 13", "verses": {"1": {"text": "Lo, mine eye hath seen all this, mine ear hath heard and understood it.", "ref": "Job 13:1"}, "2": {"text": "What ye know, the same do I know also: I am not inferior unto you.", "ref": "Job 13:2"}, "3": {"text": "Surely I would speak to the Almighty, and I desire to reason with God.", "ref": "Job 13:3"}, "4": {"text": "But ye are forgers of lies, ye are all physicians of no value.", "ref": "Job 13:4"}, "5": {"text": "O that ye would altogether hold your peace! and it should be your wisdom.", "ref": "Job 13:5"}, "6": {"text": "Hear now my reasoning, and hearken to the pleadings of my lips.", "ref": "Job 13:6"}, "7": {"text": "Will ye speak wickedly for God? and talk deceitfully for him?", "ref": "Job 13:7"}, "8": {"text": "Will ye accept his person? will ye contend for God?", "ref": "Job 13:8"}, "9": {"text": "Is it good that he should search you out? or as one man mocketh another, do ye so mock him?", "ref": "Job 13:9"}, "10": {"text": "He will surely reprove you, if ye do secretly accept persons.", "ref": "Job 13:10"}, "11": {"text": "Shall not his excellency make you afraid? and his dread fall upon you?", "ref": "Job 13:11"}, "12": {"text": "Your remembrances are like unto ashes, your bodies to bodies of clay.", "ref": "Job 13:12"}, "13": {"text": "Hold your peace, let me alone, that I may speak, and let come on me what will.", "ref": "Job 13:13"}, "14": {"text": "Wherefore do I take my flesh in my teeth, and put my life in mine hand?", "ref": "Job 13:14"}, "15": {"text": "Though he slay me, yet will I trust in him: but I will maintain mine own ways before him.", "ref": "Job 13:15"}, "16": {"text": "He also shall be my salvation: for an hypocrite shall not come before him.", "ref": "Job 13:16"}, "17": {"text": "Hear diligently my speech, and my declaration with your ears.", "ref": "Job 13:17"}, "18": {"text": "Behold now, I have ordered my cause; I know that I shall be justified.", "ref": "Job 13:18"}, "19": {"text": "Who is he that will plead with me? for now, if I hold my tongue, I shall give up the ghost.", "ref": "Job 13:19"}, "20": {"text": "Only do not two things unto me: then will I not hide myself from thee.", "ref": "Job 13:20"}, "21": {"text": "Withdraw thine hand far from me: and let not thy dread make me afraid.", "ref": "Job 13:21"}, "22": {"text": "Then call thou, and I will answer: or let me speak, and answer thou me.", "ref": "Job 13:22"}, "23": {"text": "How many are mine iniquities and sins? make me to know my transgression and my sin.", "ref": "Job 13:23"}, "24": {"text": "Wherefore hidest thou thy face, and holdest me for thine enemy?", "ref": "Job 13:24"}, "25": {"text": "Wilt thou break a leaf driven to and fro? and wilt thou pursue the dry stubble?", "ref": "Job 13:25"}, "26": {"text": "For thou writest bitter things against me, and makest me to possess the iniquities of my youth.", "ref": "Job 13:26"}, "27": {"text": "Thou puttest my feet also in the stocks, and lookest narrowly unto all my paths; thou settest a print upon the heels of my feet.", "ref": "Job 13:27"}, "28": {"text": "And he, as a rotten thing, consumeth, as a garment that is moth eaten.", "ref": "Job 13:28"}}}, "14": {"chapter": "14", "title": "Job 14", "verses": {"1": {"text": "Man that is born of a woman is of few days, and full of trouble.", "ref": "Job 14:1"}, "2": {"text": "He cometh forth like a flower, and is cut down: he fleeth also as a shadow, and continueth not.", "ref": "Job 14:2"}, "3": {"text": "And dost thou open thine eyes upon such an one, and bringest me into judgment with thee?", "ref": "Job 14:3"}, "4": {"text": "Who can bring a clean thing out of an unclean? not one.", "ref": "Job 14:4"}, "5": {"text": "Seeing his days are determined, the number of his months are with thee, thou hast appointed his bounds that he cannot pass;", "ref": "Job 14:5"}, "6": {"text": "Turn from him, that he may rest, till he shall accomplish, as an hireling, his day.", "ref": "Job 14:6"}, "7": {"text": "For there is hope of a tree, if it be cut down, that it will sprout again, and that the tender branch thereof will not cease.", "ref": "Job 14:7"}, "8": {"text": "Though the root thereof wax old in the earth, and the stock thereof die in the ground;", "ref": "Job 14:8"}, "9": {"text": "Yet through the scent of water it will bud, and bring forth boughs like a plant.", "ref": "Job 14:9"}, "10": {"text": "But man dieth, and wasteth away: yea, man giveth up the ghost, and where is he?", "ref": "Job 14:10"}, "11": {"text": "As the waters fail from the sea, and the flood decayeth and drieth up:", "ref": "Job 14:11"}, "12": {"text": "So man lieth down, and riseth not: till the heavens be no more, they shall not awake, nor be raised out of their sleep.", "ref": "Job 14:12"}, "13": {"text": "O that thou wouldest hide me in the grave, that thou wouldest keep me secret, until thy wrath be past, that thou wouldest appoint me a set time, and remember me!", "ref": "Job 14:13"}, "14": {"text": "If a man die, shall he live again? all the days of my appointed time will I wait, till my change come.", "ref": "Job 14:14"}, "15": {"text": "Thou shalt call, and I will answer thee: thou wilt have a desire to the work of thine hands.", "ref": "Job 14:15"}, "16": {"text": "For now thou numberest my steps: dost thou not watch over my sin?", "ref": "Job 14:16"}, "17": {"text": "My transgression is sealed up in a bag, and thou sewest up mine iniquity.", "ref": "Job 14:17"}, "18": {"text": "And surely the mountain falling cometh to nought, and the rock is removed out of his place.", "ref": "Job 14:18"}, "19": {"text": "The waters wear the stones: thou washest away the things which grow out of the dust of the earth; and thou destroyest the hope of man.", "ref": "Job 14:19"}, "20": {"text": "Thou prevailest for ever against him, and he passeth: thou changest his countenance, and sendest him away.", "ref": "Job 14:20"}, "21": {"text": "His sons come to honour, and he knoweth it not; and they are brought low, but he perceiveth it not of them.", "ref": "Job 14:21"}, "22": {"text": "But his flesh upon him shall have pain, and his soul within him shall mourn.", "ref": "Job 14:22"}}}, "15": {"chapter": "15", "title": "Job 15", "verses": {"1": {"text": "Then answered Eliphaz the Temanite, and said,", "ref": "Job 15:1"}, "2": {"text": "Should a wise man utter vain knowledge, and fill his belly with the east wind?", "ref": "Job 15:2"}, "3": {"text": "Should he reason with unprofitable talk? or with speeches wherewith he can do no good?", "ref": "Job 15:3"}, "4": {"text": "Yea, thou castest off fear, and restrainest prayer before God.", "ref": "Job 15:4"}, "5": {"text": "For thy mouth uttereth thine iniquity, and thou choosest the tongue of the crafty.", "ref": "Job 15:5"}, "6": {"text": "Thine own mouth condemneth thee, and not I: yea, thine own lips testify against thee.", "ref": "Job 15:6"}, "7": {"text": "Art thou the first man that was born? or wast thou made before the hills?", "ref": "Job 15:7"}, "8": {"text": "Hast thou heard the secret of God? and dost thou restrain wisdom to thyself?", "ref": "Job 15:8"}, "9": {"text": "What knowest thou, that we know not? what understandest thou, which is not in us?", "ref": "Job 15:9"}, "10": {"text": "With us are both the grayheaded and very aged men, much elder than thy father.", "ref": "Job 15:10"}, "11": {"text": "Are the consolations of God small with thee? is there any secret thing with thee?", "ref": "Job 15:11"}, "12": {"text": "Why doth thine heart carry thee away? and what do thy eyes wink at,", "ref": "Job 15:12"}, "13": {"text": "That thou turnest thy spirit against God, and lettest such words go out of thy mouth?", "ref": "Job 15:13"}, "14": {"text": "What is man, that he should be clean? and he which is born of a woman, that he should be righteous?", "ref": "Job 15:14"}, "15": {"text": "Behold, he putteth no trust in his saints; yea, the heavens are not clean in his sight.", "ref": "Job 15:15"}, "16": {"text": "How much more abominable and filthy is man, which drinketh iniquity like water?", "ref": "Job 15:16"}, "17": {"text": "I will shew thee, hear me; and that which I have seen I will declare;", "ref": "Job 15:17"}, "18": {"text": "Which wise men have told from their fathers, and have not hid it:", "ref": "Job 15:18"}, "19": {"text": "Unto whom alone the earth was given, and no stranger passed among them.", "ref": "Job 15:19"}, "20": {"text": "The wicked man travaileth with pain all his days, and the number of years is hidden to the oppressor.", "ref": "Job 15:20"}, "21": {"text": "A dreadful sound is in his ears: in prosperity the destroyer shall come upon him.", "ref": "Job 15:21"}, "22": {"text": "He believeth not that he shall return out of darkness, and he is waited for of the sword.", "ref": "Job 15:22"}, "23": {"text": "He wandereth abroad for bread, saying, Where is it? he knoweth that the day of darkness is ready at his hand.", "ref": "Job 15:23"}, "24": {"text": "Trouble and anguish shall make him afraid; they shall prevail against him, as a king ready to the battle.", "ref": "Job 15:24"}, "25": {"text": "For he stretcheth out his hand against God, and strengtheneth himself against the Almighty.", "ref": "Job 15:25"}, "26": {"text": "He runneth upon him, even on his neck, upon the thick bosses of his bucklers:", "ref": "Job 15:26"}, "27": {"text": "Because he covereth his face with his fatness, and maketh collops of fat on his flanks.", "ref": "Job 15:27"}, "28": {"text": "And he dwelleth in desolate cities, and in houses which no man inhabiteth, which are ready to become heaps.", "ref": "Job 15:28"}, "29": {"text": "He shall not be rich, neither shall his substance continue, neither shall he prolong the perfection thereof upon the earth.", "ref": "Job 15:29"}, "30": {"text": "He shall not depart out of darkness; the flame shall dry up his branches, and by the breath of his mouth shall he go away.", "ref": "Job 15:30"}, "31": {"text": "Let not him that is deceived trust in vanity: for vanity shall be his recompence.", "ref": "Job 15:31"}, "32": {"text": "It shall be accomplished before his time, and his branch shall not be green.", "ref": "Job 15:32"}, "33": {"text": "He shall shake off his unripe grape as the vine, and shall cast off his flower as the olive.", "ref": "Job 15:33"}, "34": {"text": "For the congregation of hypocrites shall be desolate, and fire shall consume the tabernacles of bribery.", "ref": "Job 15:34"}, "35": {"text": "They conceive mischief, and bring forth vanity, and their belly prepareth deceit.", "ref": "Job 15:35"}}}, "16": {"chapter": "16", "title": "Job 16", "verses": {"1": {"text": "Then Job answered and said,", "ref": "Job 16:1"}, "2": {"text": "I have heard many such things: miserable comforters are ye all.", "ref": "Job 16:2"}, "3": {"text": "Shall vain words have an end? or what emboldeneth thee that thou answerest?", "ref": "Job 16:3"}, "4": {"text": "I also could speak as ye do: if your soul were in my soul’s stead, I could heap up words against you, and shake mine head at you.", "ref": "Job 16:4"}, "5": {"text": "But I would strengthen you with my mouth, and the moving of my lips should asswage your grief.", "ref": "Job 16:5"}, "6": {"text": "Though I speak, my grief is not asswaged: and though I forbear, what am I eased?", "ref": "Job 16:6"}, "7": {"text": "But now he hath made me weary: thou hast made desolate all my company.", "ref": "Job 16:7"}, "8": {"text": "And thou hast filled me with wrinkles, which is a witness against me: and my leanness rising up in me beareth witness to my face.", "ref": "Job 16:8"}, "9": {"text": "He teareth me in his wrath, who hateth me: he gnasheth upon me with his teeth; mine enemy sharpeneth his eyes upon me.", "ref": "Job 16:9"}, "10": {"text": "They have gaped upon me with their mouth; they have smitten me upon the cheek reproachfully; they have gathered themselves together against me.", "ref": "Job 16:10"}, "11": {"text": "God hath delivered me to the ungodly, and turned me over into the hands of the wicked.", "ref": "Job 16:11"}, "12": {"text": "I was at ease, but he hath broken me asunder: he hath also taken me by my neck, and shaken me to pieces, and set me up for his mark.", "ref": "Job 16:12"}, "13": {"text": "His archers compass me round about, he cleaveth my reins asunder, and doth not spare; he poureth out my gall upon the ground.", "ref": "Job 16:13"}, "14": {"text": "He breaketh me with breach upon breach, he runneth upon me like a giant.", "ref": "Job 16:14"}, "15": {"text": "I have sewed sackcloth upon my skin, and defiled my horn in the dust.", "ref": "Job 16:15"}, "16": {"text": "My face is foul with weeping, and on my eyelids is the shadow of death;", "ref": "Job 16:16"}, "17": {"text": "Not for any injustice in mine hands: also my prayer is pure.", "ref": "Job 16:17"}, "18": {"text": "O earth, cover not thou my blood, and let my cry have no place.", "ref": "Job 16:18"}, "19": {"text": "Also now, behold, my witness is in heaven, and my record is on high.", "ref": "Job 16:19"}, "20": {"text": "My friends scorn me: but mine eye poureth out tears unto God.", "ref": "Job 16:20"}, "21": {"text": "O that one might plead for a man with God, as a man pleadeth for his neighbour!", "ref": "Job 16:21"}, "22": {"text": "When a few years are come, then I shall go the way whence I shall not return.", "ref": "Job 16:22"}}}, "17": {"chapter": "17", "title": "Job 17", "verses": {"1": {"text": "My breath is corrupt, my days are extinct, the graves are ready for me.", "ref": "Job 17:1"}, "2": {"text": "Are there not mockers with me? and doth not mine eye continue in their provocation?", "ref": "Job 17:2"}, "3": {"text": "Lay down now, put me in a surety with thee; who is he that will strike hands with me?", "ref": "Job 17:3"}, "4": {"text": "For thou hast hid their heart from understanding: therefore shalt thou not exalt them.", "ref": "Job 17:4"}, "5": {"text": "He that speaketh flattery to his friends, even the eyes of his children shall fail.", "ref": "Job 17:5"}, "6": {"text": "He hath made me also a byword of the people; and aforetime I was as a tabret.", "ref": "Job 17:6"}, "7": {"text": "Mine eye also is dim by reason of sorrow, and all my members are as a shadow.", "ref": "Job 17:7"}, "8": {"text": "Upright men shall be astonied at this, and the innocent shall stir up himself against the hypocrite.", "ref": "Job 17:8"}, "9": {"text": "The righteous also shall hold on his way, and he that hath clean hands shall be stronger and stronger.", "ref": "Job 17:9"}, "10": {"text": "But as for you all, do ye return, and come now: for I cannot find one wise man among you.", "ref": "Job 17:10"}, "11": {"text": "My days are past, my purposes are broken off, even the thoughts of my heart.", "ref": "Job 17:11"}, "12": {"text": "They change the night into day: the light is short because of darkness.", "ref": "Job 17:12"}, "13": {"text": "If I wait, the grave is mine house: I have made my bed in the darkness.", "ref": "Job 17:13"}, "14": {"text": "I have said to corruption, Thou art my father: to the worm, Thou art my mother, and my sister.", "ref": "Job 17:14"}, "15": {"text": "And where is now my hope? as for my hope, who shall see it?", "ref": "Job 17:15"}, "16": {"text": "They shall go down to the bars of the pit, when our rest together is in the dust.", "ref": "Job 17:16"}}}, "18": {"chapter": "18", "title": "Job 18", "verses": {"1": {"text": "Then answered Bildad the Shuhite, and said,", "ref": "Job 18:1"}, "2": {"text": "How long will it be ere ye make an end of words? mark, and afterwards we will speak.", "ref": "Job 18:2"}, "3": {"text": "Wherefore are we counted as beasts, and reputed vile in your sight?", "ref": "Job 18:3"}, "4": {"text": "He teareth himself in his anger: shall the earth be forsaken for thee? and shall the rock be removed out of his place?", "ref": "Job 18:4"}, "5": {"text": "Yea, the light of the wicked shall be put out, and the spark of his fire shall not shine.", "ref": "Job 18:5"}, "6": {"text": "The light shall be dark in his tabernacle, and his candle shall be put out with him.", "ref": "Job 18:6"}, "7": {"text": "The steps of his strength shall be straitened, and his own counsel shall cast him down.", "ref": "Job 18:7"}, "8": {"text": "For he is cast into a net by his own feet, and he walketh upon a snare.", "ref": "Job 18:8"}, "9": {"text": "The gin shall take him by the heel, and the robber shall prevail against him.", "ref": "Job 18:9"}, "10": {"text": "The snare is laid for him in the ground, and a trap for him in the way.", "ref": "Job 18:10"}, "11": {"text": "Terrors shall make him afraid on every side, and shall drive him to his feet.", "ref": "Job 18:11"}, "12": {"text": "His strength shall be hungerbitten, and destruction shall be ready at his side.", "ref": "Job 18:12"}, "13": {"text": "It shall devour the strength of his skin: even the firstborn of death shall devour his strength.", "ref": "Job 18:13"}, "14": {"text": "His confidence shall be rooted out of his tabernacle, and it shall bring him to the king of terrors.", "ref": "Job 18:14"}, "15": {"text": "It shall dwell in his tabernacle, because it is none of his: brimstone shall be scattered upon his habitation.", "ref": "Job 18:15"}, "16": {"text": "His roots shall be dried up beneath, and above shall his branch be cut off.", "ref": "Job 18:16"}, "17": {"text": "His remembrance shall perish from the earth, and he shall have no name in the street.", "ref": "Job 18:17"}, "18": {"text": "He shall be driven from light into darkness, and chased out of the world.", "ref": "Job 18:18"}, "19": {"text": "He shall neither have son nor nephew among his people, nor any remaining in his dwellings.", "ref": "Job 18:19"}, "20": {"text": "They that come after him shall be astonied at his day, as they that went before were affrighted.", "ref": "Job 18:20"}, "21": {"text": "Surely such are the dwellings of the wicked, and this is the place of him that knoweth not God.", "ref": "Job 18:21"}}}, "19": {"chapter": "19", "title": "Job 19", "verses": {"1": {"text": "Then Job answered and said,", "ref": "Job 19:1"}, "2": {"text": "How long will ye vex my soul, and break me in pieces with words?", "ref": "Job 19:2"}, "3": {"text": "These ten times have ye reproached me: ye are not ashamed that ye make yourselves strange to me.", "ref": "Job 19:3"}, "4": {"text": "And be it indeed that I have erred, mine error remaineth with myself.", "ref": "Job 19:4"}, "5": {"text": "If indeed ye will magnify yourselves against me, and plead against me my reproach:", "ref": "Job 19:5"}, "6": {"text": "Know now that God hath overthrown me, and hath compassed me with his net.", "ref": "Job 19:6"}, "7": {"text": "Behold, I cry out of wrong, but I am not heard: I cry aloud, but there is no judgment.", "ref": "Job 19:7"}, "8": {"text": "He hath fenced up my way that I cannot pass, and he hath set darkness in my paths.", "ref": "Job 19:8"}, "9": {"text": "He hath stripped me of my glory, and taken the crown from my head.", "ref": "Job 19:9"}, "10": {"text": "He hath destroyed me on every side, and I am gone: and mine hope hath he removed like a tree.", "ref": "Job 19:10"}, "11": {"text": "He hath also kindled his wrath against me, and he counteth me unto him as one of his enemies.", "ref": "Job 19:11"}, "12": {"text": "His troops come together, and raise up their way against me, and encamp round about my tabernacle.", "ref": "Job 19:12"}, "13": {"text": "He hath put my brethren far from me, and mine acquaintance are verily estranged from me.", "ref": "Job 19:13"}, "14": {"text": "My kinsfolk have failed, and my familiar friends have forgotten me.", "ref": "Job 19:14"}, "15": {"text": "They that dwell in mine house, and my maids, count me for a stranger: I am an alien in their sight.", "ref": "Job 19:15"}, "16": {"text": "I called my servant, and he gave me no answer; I intreated him with my mouth.", "ref": "Job 19:16"}, "17": {"text": "My breath is strange to my wife, though I intreated for the children’s sake of mine own body.", "ref": "Job 19:17"}, "18": {"text": "Yea, young children despised me; I arose, and they spake against me.", "ref": "Job 19:18"}, "19": {"text": "All my inward friends abhorred me: and they whom I loved are turned against me.", "ref": "Job 19:19"}, "20": {"text": "My bone cleaveth to my skin and to my flesh, and I am escaped with the skin of my teeth.", "ref": "Job 19:20"}, "21": {"text": "Have pity upon me, have pity upon me, O ye my friends; for the hand of God hath touched me.", "ref": "Job 19:21"}, "22": {"text": "Why do ye persecute me as God, and are not satisfied with my flesh?", "ref": "Job 19:22"}, "23": {"text": "Oh that my words were now written! oh that they were printed in a book!", "ref": "Job 19:23"}, "24": {"text": "That they were graven with an iron pen and lead in the rock for ever!", "ref": "Job 19:24"}, "25": {"text": "For I know that my redeemer liveth, and that he shall stand at the latter day upon the earth:", "ref": "Job 19:25"}, "26": {"text": "And though after my skin worms destroy this body, yet in my flesh shall I see God:", "ref": "Job 19:26"}, "27": {"text": "Whom I shall see for myself, and mine eyes shall behold, and not another; though my reins be consumed within me.", "ref": "Job 19:27"}, "28": {"text": "But ye should say, Why persecute we him, seeing the root of the matter is found in me?", "ref": "Job 19:28"}, "29": {"text": "Be ye afraid of the sword: for wrath bringeth the punishments of the sword, that ye may know there is a judgment.", "ref": "Job 19:29"}}}, "20": {"chapter": "20", "title": "Job 20", "verses": {"1": {"text": "Then answered Zophar the Naamathite, and said,", "ref": "Job 20:1"}, "2": {"text": "Therefore do my thoughts cause me to answer, and for this I make haste.", "ref": "Job 20:2"}, "3": {"text": "I have heard the check of my reproach, and the spirit of my understanding causeth me to answer.", "ref": "Job 20:3"}, "4": {"text": "Knowest thou not this of old, since man was placed upon earth,", "ref": "Job 20:4"}, "5": {"text": "That the triumphing of the wicked is short, and the joy of the hypocrite but for a moment?", "ref": "Job 20:5"}, "6": {"text": "Though his excellency mount up to the heavens, and his head reach unto the clouds;", "ref": "Job 20:6"}, "7": {"text": "Yet he shall perish for ever like his own dung: they which have seen him shall say, Where is he?", "ref": "Job 20:7"}, "8": {"text": "He shall fly away as a dream, and shall not be found: yea, he shall be chased away as a vision of the night.", "ref": "Job 20:8"}, "9": {"text": "The eye also which saw him shall see him no more; neither shall his place any more behold him.", "ref": "Job 20:9"}, "10": {"text": "His children shall seek to please the poor, and his hands shall restore their goods.", "ref": "Job 20:10"}, "11": {"text": "His bones are full of the sin of his youth, which shall lie down with him in the dust.", "ref": "Job 20:11"}, "12": {"text": "Though wickedness be sweet in his mouth, though he hide it under his tongue;", "ref": "Job 20:12"}, "13": {"text": "Though he spare it, and forsake it not; but keep it still within his mouth:", "ref": "Job 20:13"}, "14": {"text": "Yet his meat in his bowels is turned, it is the gall of asps within him.", "ref": "Job 20:14"}, "15": {"text": "He hath swallowed down riches, and he shall vomit them up again: God shall cast them out of his belly.", "ref": "Job 20:15"}, "16": {"text": "He shall suck the poison of asps: the viper’s tongue shall slay him.", "ref": "Job 20:16"}, "17": {"text": "He shall not see the rivers, the floods, the brooks of honey and butter.", "ref": "Job 20:17"}, "18": {"text": "That which he laboured for shall he restore, and shall not swallow it down: according to his substance shall the restitution be, and he shall not rejoice therein.", "ref": "Job 20:18"}, "19": {"text": "Because he hath oppressed and hath forsaken the poor; because he hath violently taken away an house which he builded not;", "ref": "Job 20:19"}, "20": {"text": "Surely he shall not feel quietness in his belly, he shall not save of that which he desired.", "ref": "Job 20:20"}, "21": {"text": "There shall none of his meat be left; therefore shall no man look for his goods.", "ref": "Job 20:21"}, "22": {"text": "In the fulness of his sufficiency he shall be in straits: every hand of the wicked shall come upon him.", "ref": "Job 20:22"}, "23": {"text": "When he is about to fill his belly, God shall cast the fury of his wrath upon him, and shall rain it upon him while he is eating.", "ref": "Job 20:23"}, "24": {"text": "He shall flee from the iron weapon, and the bow of steel shall strike him through.", "ref": "Job 20:24"}, "25": {"text": "It is drawn, and cometh out of the body; yea, the glittering sword cometh out of his gall: terrors are upon him.", "ref": "Job 20:25"}, "26": {"text": "All darkness shall be hid in his secret places: a fire not blown shall consume him; it shall go ill with him that is left in his tabernacle.", "ref": "Job 20:26"}, "27": {"text": "The heaven shall reveal his iniquity; and the earth shall rise up against him.", "ref": "Job 20:27"}, "28": {"text": "The increase of his house shall depart, and his goods shall flow away in the day of his wrath.", "ref": "Job 20:28"}, "29": {"text": "This is the portion of a wicked man from God, and the heritage appointed unto him by God.", "ref": "Job 20:29"}}}, "21": {"chapter": "21", "title": "Job 21", "verses": {"1": {"text": "But Job answered and said,", "ref": "Job 21:1"}, "2": {"text": "Hear diligently my speech, and let this be your consolations.", "ref": "Job 21:2"}, "3": {"text": "Suffer me that I may speak; and after that I have spoken, mock on.", "ref": "Job 21:3"}, "4": {"text": "As for me, is my complaint to man? and if it were so, why should not my spirit be troubled?", "ref": "Job 21:4"}, "5": {"text": "Mark me, and be astonished, and lay your hand upon your mouth.", "ref": "Job 21:5"}, "6": {"text": "Even when I remember I am afraid, and trembling taketh hold on my flesh.", "ref": "Job 21:6"}, "7": {"text": "Wherefore do the wicked live, become old, yea, are mighty in power?", "ref": "Job 21:7"}, "8": {"text": "Their seed is established in their sight with them, and their offspring before their eyes.", "ref": "Job 21:8"}, "9": {"text": "Their houses are safe from fear, neither is the rod of God upon them.", "ref": "Job 21:9"}, "10": {"text": "Their bull gendereth, and faileth not; their cow calveth, and casteth not her calf.", "ref": "Job 21:10"}, "11": {"text": "They send forth their little ones like a flock, and their children dance.", "ref": "Job 21:11"}, "12": {"text": "They take the timbrel and harp, and rejoice at the sound of the organ.", "ref": "Job 21:12"}, "13": {"text": "They spend their days in wealth, and in a moment go down to the grave.", "ref": "Job 21:13"}, "14": {"text": "Therefore they say unto God, Depart from us; for we desire not the knowledge of thy ways.", "ref": "Job 21:14"}, "15": {"text": "What is the Almighty, that we should serve him? and what profit should we have, if we pray unto him?", "ref": "Job 21:15"}, "16": {"text": "Lo, their good is not in their hand: the counsel of the wicked is far from me.", "ref": "Job 21:16"}, "17": {"text": "How oft is the candle of the wicked put out! and how oft cometh their destruction upon them! God distributeth sorrows in his anger.", "ref": "Job 21:17"}, "18": {"text": "They are as stubble before the wind, and as chaff that the storm carrieth away.", "ref": "Job 21:18"}, "19": {"text": "God layeth up his iniquity for his children: he rewardeth him, and he shall know it.", "ref": "Job 21:19"}, "20": {"text": "His eyes shall see his destruction, and he shall drink of the wrath of the Almighty.", "ref": "Job 21:20"}, "21": {"text": "For what pleasure hath he in his house after him, when the number of his months is cut off in the midst?", "ref": "Job 21:21"}, "22": {"text": "Shall any teach God knowledge? seeing he judgeth those that are high.", "ref": "Job 21:22"}, "23": {"text": "One dieth in his full strength, being wholly at ease and quiet.", "ref": "Job 21:23"}, "24": {"text": "His breasts are full of milk, and his bones are moistened with marrow.", "ref": "Job 21:24"}, "25": {"text": "And another dieth in the bitterness of his soul, and never eateth with pleasure.", "ref": "Job 21:25"}, "26": {"text": "They shall lie down alike in the dust, and the worms shall cover them.", "ref": "Job 21:26"}, "27": {"text": "Behold, I know your thoughts, and the devices which ye wrongfully imagine against me.", "ref": "Job 21:27"}, "28": {"text": "For ye say, Where is the house of the prince? and where are the dwelling places of the wicked?", "ref": "Job 21:28"}, "29": {"text": "Have ye not asked them that go by the way? and do ye not know their tokens,", "ref": "Job 21:29"}, "30": {"text": "That the wicked is reserved to the day of destruction? they shall be brought forth to the day of wrath.", "ref": "Job 21:30"}, "31": {"text": "Who shall declare his way to his face? and who shall repay him what he hath done?", "ref": "Job 21:31"}, "32": {"text": "Yet shall he be brought to the grave, and shall remain in the tomb.", "ref": "Job 21:32"}, "33": {"text": "The clods of the valley shall be sweet unto him, and every man shall draw after him, as there are innumerable before him.", "ref": "Job 21:33"}, "34": {"text": "How then comfort ye me in vain, seeing in your answers there remaineth falsehood?", "ref": "Job 21:34"}}}, "22": {"chapter": "22", "title": "Job 22", "verses": {"1": {"text": "Then Eliphaz the Temanite answered and said,", "ref": "Job 22:1"}, "2": {"text": "Can a man be profitable unto God, as he that is wise may be profitable unto himself?", "ref": "Job 22:2"}, "3": {"text": "Is it any pleasure to the Almighty, that thou art righteous? or is it gain to him, that thou makest thy ways perfect?", "ref": "Job 22:3"}, "4": {"text": "Will he reprove thee for fear of thee? will he enter with thee into judgment?", "ref": "Job 22:4"}, "5": {"text": "Is not thy wickedness great? and thine iniquities infinite?", "ref": "Job 22:5"}, "6": {"text": "For thou hast taken a pledge from thy brother for nought, and stripped the naked of their clothing.", "ref": "Job 22:6"}, "7": {"text": "Thou hast not given water to the weary to drink, and thou hast withholden bread from the hungry.", "ref": "Job 22:7"}, "8": {"text": "But as for the mighty man, he had the earth; and the honourable man dwelt in it.", "ref": "Job 22:8"}, "9": {"text": "Thou hast sent widows away empty, and the arms of the fatherless have been broken.", "ref": "Job 22:9"}, "10": {"text": "Therefore snares are round about thee, and sudden fear troubleth thee;", "ref": "Job 22:10"}, "11": {"text": "Or darkness, that thou canst not see; and abundance of waters cover thee.", "ref": "Job 22:11"}, "12": {"text": "Is not God in the height of heaven? and behold the height of the stars, how high they are!", "ref": "Job 22:12"}, "13": {"text": "And thou sayest, How doth God know? can he judge through the dark cloud?", "ref": "Job 22:13"}, "14": {"text": "Thick clouds are a covering to him, that he seeth not; and he walketh in the circuit of heaven.", "ref": "Job 22:14"}, "15": {"text": "Hast thou marked the old way which wicked men have trodden?", "ref": "Job 22:15"}, "16": {"text": "Which were cut down out of time, whose foundation was overflown with a flood:", "ref": "Job 22:16"}, "17": {"text": "Which said unto God, Depart from us: and what can the Almighty do for them?", "ref": "Job 22:17"}, "18": {"text": "Yet he filled their houses with good things: but the counsel of the wicked is far from me.", "ref": "Job 22:18"}, "19": {"text": "The righteous see it, and are glad: and the innocent laugh them to scorn.", "ref": "Job 22:19"}, "20": {"text": "Whereas our substance is not cut down, but the remnant of them the fire consumeth.", "ref": "Job 22:20"}, "21": {"text": "Acquaint now thyself with him, and be at peace: thereby good shall come unto thee.", "ref": "Job 22:21"}, "22": {"text": "Receive, I pray thee, the law from his mouth, and lay up his words in thine heart.", "ref": "Job 22:22"}, "23": {"text": "If thou return to the Almighty, thou shalt be built up, thou shalt put away iniquity far from thy tabernacles.", "ref": "Job 22:23"}, "24": {"text": "Then shalt thou lay up gold as dust, and the gold of Ophir as the stones of the brooks.", "ref": "Job 22:24"}, "25": {"text": "Yea, the Almighty shall be thy defence, and thou shalt have plenty of silver.", "ref": "Job 22:25"}, "26": {"text": "For then shalt thou have thy delight in the Almighty, and shalt lift up thy face unto God.", "ref": "Job 22:26"}, "27": {"text": "Thou shalt make thy prayer unto him, and he shall hear thee, and thou shalt pay thy vows.", "ref": "Job 22:27"}, "28": {"text": "Thou shalt also decree a thing, and it shall be established unto thee: and the light shall shine upon thy ways.", "ref": "Job 22:28"}, "29": {"text": "When men are cast down, then thou shalt say, There is lifting up; and he shall save the humble person.", "ref": "Job 22:29"}, "30": {"text": "He shall deliver the island of the innocent: and it is delivered by the pureness of thine hands.", "ref": "Job 22:30"}}}, "23": {"chapter": "23", "title": "Job 23", "verses": {"1": {"text": "Then Job answered and said,", "ref": "Job 23:1"}, "2": {"text": "Even to day is my complaint bitter: my stroke is heavier than my groaning.", "ref": "Job 23:2"}, "3": {"text": "Oh that I knew where I might find him! that I might come even to his seat!", "ref": "Job 23:3"}, "4": {"text": "I would order my cause before him, and fill my mouth with arguments.", "ref": "Job 23:4"}, "5": {"text": "I would know the words which he would answer me, and understand what he would say unto me.", "ref": "Job 23:5"}, "6": {"text": "Will he plead against me with his great power? No; but he would put strength in me.", "ref": "Job 23:6"}, "7": {"text": "There the righteous might dispute with him; so should I be delivered for ever from my judge.", "ref": "Job 23:7"}, "8": {"text": "Behold, I go forward, but he is not there; and backward, but I cannot perceive him:", "ref": "Job 23:8"}, "9": {"text": "On the left hand, where he doth work, but I cannot behold him: he hideth himself on the right hand, that I cannot see him:", "ref": "Job 23:9"}, "10": {"text": "But he knoweth the way that I take: when he hath tried me, I shall come forth as gold.", "ref": "Job 23:10"}, "11": {"text": "My foot hath held his steps, his way have I kept, and not declined.", "ref": "Job 23:11"}, "12": {"text": "Neither have I gone back from the commandment of his lips; I have esteemed the words of his mouth more than my necessary food.", "ref": "Job 23:12"}, "13": {"text": "But he is in one mind, and who can turn him? and what his soul desireth, even that he doeth.", "ref": "Job 23:13"}, "14": {"text": "For he performeth the thing that is appointed for me: and many such things are with him.", "ref": "Job 23:14"}, "15": {"text": "Therefore am I troubled at his presence: when I consider, I am afraid of him.", "ref": "Job 23:15"}, "16": {"text": "For God maketh my heart soft, and the Almighty troubleth me:", "ref": "Job 23:16"}, "17": {"text": "Because I was not cut off before the darkness, neither hath he covered the darkness from my face.", "ref": "Job 23:17"}}}, "24": {"chapter": "24", "title": "Job 24", "verses": {"1": {"text": "Why, seeing times are not hidden from the Almighty, do they that know him not see his days?", "ref": "Job 24:1"}, "2": {"text": "Some remove the landmarks; they violently take away flocks, and feed thereof.", "ref": "Job 24:2"}, "3": {"text": "They drive away the ass of the fatherless, they take the widow’s ox for a pledge.", "ref": "Job 24:3"}, "4": {"text": "They turn the needy out of the way: the poor of the earth hide themselves together.", "ref": "Job 24:4"}, "5": {"text": "Behold, as wild asses in the desert, go they forth to their work; rising betimes for a prey: the wilderness yieldeth food for them and for their children.", "ref": "Job 24:5"}, "6": {"text": "They reap every one his corn in the field: and they gather the vintage of the wicked.", "ref": "Job 24:6"}, "7": {"text": "They cause the naked to lodge without clothing, that they have no covering in the cold.", "ref": "Job 24:7"}, "8": {"text": "They are wet with the showers of the mountains, and embrace the rock for want of a shelter.", "ref": "Job 24:8"}, "9": {"text": "They pluck the fatherless from the breast, and take a pledge of the poor.", "ref": "Job 24:9"}, "10": {"text": "They cause him to go naked without clothing, and they take away the sheaf from the hungry;", "ref": "Job 24:10"}, "11": {"text": "Which make oil within their walls, and tread their winepresses, and suffer thirst.", "ref": "Job 24:11"}, "12": {"text": "Men groan from out of the city, and the soul of the wounded crieth out: yet God layeth not folly to them.", "ref": "Job 24:12"}, "13": {"text": "They are of those that rebel against the light; they know not the ways thereof, nor abide in the paths thereof.", "ref": "Job 24:13"}, "14": {"text": "The murderer rising with the light killeth the poor and needy, and in the night is as a thief.", "ref": "Job 24:14"}, "15": {"text": "The eye also of the adulterer waiteth for the twilight, saying, No eye shall see me: and disguiseth his face.", "ref": "Job 24:15"}, "16": {"text": "In the dark they dig through houses, which they had marked for themselves in the daytime: they know not the light.", "ref": "Job 24:16"}, "17": {"text": "For the morning is to them even as the shadow of death: if one know them, they are in the terrors of the shadow of death.", "ref": "Job 24:17"}, "18": {"text": "He is swift as the waters; their portion is cursed in the earth: he beholdeth not the way of the vineyards.", "ref": "Job 24:18"}, "19": {"text": "Drought and heat consume the snow waters: so doth the grave those which have sinned.", "ref": "Job 24:19"}, "20": {"text": "The womb shall forget him; the worm shall feed sweetly on him; he shall be no more remembered; and wickedness shall be broken as a tree.", "ref": "Job 24:20"}, "21": {"text": "He evil entreateth the barren that beareth not: and doeth not good to the widow.", "ref": "Job 24:21"}, "22": {"text": "He draweth also the mighty with his power: he riseth up, and no man is sure of life.", "ref": "Job 24:22"}, "23": {"text": "Though it be given him to be in safety, whereon he resteth; yet his eyes are upon their ways.", "ref": "Job 24:23"}, "24": {"text": "They are exalted for a little while, but are gone and brought low; they are taken out of the way as all other, and cut off as the tops of the ears of corn.", "ref": "Job 24:24"}, "25": {"text": "And if it be not so now, who will make me a liar, and make my speech nothing worth?", "ref": "Job 24:25"}}}, "25": {"chapter": "25", "title": "Job 25", "verses": {"1": {"text": "Then answered Bildad the Shuhite, and said,", "ref": "Job 25:1"}, "2": {"text": "Dominion and fear are with him, he maketh peace in his high places.", "ref": "Job 25:2"}, "3": {"text": "Is there any number of his armies? and upon whom doth not his light arise?", "ref": "Job 25:3"}, "4": {"text": "How then can man be justified with God? or how can he be clean that is born of a woman?", "ref": "Job 25:4"}, "5": {"text": "Behold even to the moon, and it shineth not; yea, the stars are not pure in his sight.", "ref": "Job 25:5"}, "6": {"text": "How much less man, that is a worm? and the son of man, which is a worm?", "ref": "Job 25:6"}}}, "26": {"chapter": "26", "title": "Job 26", "verses": {"1": {"text": "But Job answered and said,", "ref": "Job 26:1"}, "2": {"text": "How hast thou helped him that is without power? how savest thou the arm that hath no strength?", "ref": "Job 26:2"}, "3": {"text": "How hast thou counselled him that hath no wisdom? and how hast thou plentifully declared the thing as it is?", "ref": "Job 26:3"}, "4": {"text": "To whom hast thou uttered words? and whose spirit came from thee?", "ref": "Job 26:4"}, "5": {"text": "Dead things are formed from under the waters, and the inhabitants thereof.", "ref": "Job 26:5"}, "6": {"text": "Hell is naked before him, and destruction hath no covering.", "ref": "Job 26:6"}, "7": {"text": "He stretcheth out the north over the empty place, and hangeth the earth upon nothing.", "ref": "Job 26:7"}, "8": {"text": "He bindeth up the waters in his thick clouds; and the cloud is not rent under them.", "ref": "Job 26:8"}, "9": {"text": "He holdeth back the face of his throne, and spreadeth his cloud upon it.", "ref": "Job 26:9"}, "10": {"text": "He hath compassed the waters with bounds, until the day and night come to an end.", "ref": "Job 26:10"}, "11": {"text": "The pillars of heaven tremble and are astonished at his reproof.", "ref": "Job 26:11"}, "12": {"text": "He divideth the sea with his power, and by his understanding he smiteth through the proud.", "ref": "Job 26:12"}, "13": {"text": "By his spirit he hath garnished the heavens; his hand hath formed the crooked serpent.", "ref": "Job 26:13"}, "14": {"text": "Lo, these are parts of his ways: but how little a portion is heard of him? but the thunder of his power who can understand?", "ref": "Job 26:14"}}}, "27": {"chapter": "27", "title": "Job 27", "verses": {"1": {"text": "Moreover Job continued his parable, and said,", "ref": "Job 27:1"}, "2": {"text": "As God liveth, who hath taken away my judgment; and the Almighty, who hath vexed my soul;", "ref": "Job 27:2"}, "3": {"text": "All the while my breath is in me, and the spirit of God is in my nostrils;", "ref": "Job 27:3"}, "4": {"text": "My lips shall not speak wickedness, nor my tongue utter deceit.", "ref": "Job 27:4"}, "5": {"text": "God forbid that I should justify you: till I die I will not remove mine integrity from me.", "ref": "Job 27:5"}, "6": {"text": "My righteousness I hold fast, and will not let it go: my heart shall not reproach me so long as I live.", "ref": "Job 27:6"}, "7": {"text": "Let mine enemy be as the wicked, and he that riseth up against me as the unrighteous.", "ref": "Job 27:7"}, "8": {"text": "For what is the hope of the hypocrite, though he hath gained, when God taketh away his soul?", "ref": "Job 27:8"}, "9": {"text": "Will God hear his cry when trouble cometh upon him?", "ref": "Job 27:9"}, "10": {"text": "Will he delight himself in the Almighty? will he always call upon God?", "ref": "Job 27:10"}, "11": {"text": "I will teach you by the hand of God: that which is with the Almighty will I not conceal.", "ref": "Job 27:11"}, "12": {"text": "Behold, all ye yourselves have seen it; why then are ye thus altogether vain?", "ref": "Job 27:12"}, "13": {"text": "This is the portion of a wicked man with God, and the heritage of oppressors, which they shall receive of the Almighty.", "ref": "Job 27:13"}, "14": {"text": "If his children be multiplied, it is for the sword: and his offspring shall not be satisfied with bread.", "ref": "Job 27:14"}, "15": {"text": "Those that remain of him shall be buried in death: and his widows shall not weep.", "ref": "Job 27:15"}, "16": {"text": "Though he heap up silver as the dust, and prepare raiment as the clay;", "ref": "Job 27:16"}, "17": {"text": "He may prepare it, but the just shall put it on, and the innocent shall divide the silver.", "ref": "Job 27:17"}, "18": {"text": "He buildeth his house as a moth, and as a booth that the keeper maketh.", "ref": "Job 27:18"}, "19": {"text": "The rich man shall lie down, but he shall not be gathered: he openeth his eyes, and he is not.", "ref": "Job 27:19"}, "20": {"text": "Terrors take hold on him as waters, a tempest stealeth him away in the night.", "ref": "Job 27:20"}, "21": {"text": "The east wind carrieth him away, and he departeth: and as a storm hurleth him out of his place.", "ref": "Job 27:21"}, "22": {"text": "For God shall cast upon him, and not spare: he would fain flee out of his hand.", "ref": "Job 27:22"}, "23": {"text": "Men shall clap their hands at him, and shall hiss him out of his place.", "ref": "Job 27:23"}}}, "28": {"chapter": "28", "title": "Job 28", "verses": {"1": {"text": "Surely there is a vein for the silver, and a place for gold where they fine it.", "ref": "Job 28:1"}, "2": {"text": "Iron is taken out of the earth, and brass is molten out of the stone.", "ref": "Job 28:2"}, "3": {"text": "He setteth an end to darkness, and searcheth out all perfection: the stones of darkness, and the shadow of death.", "ref": "Job 28:3"}, "4": {"text": "The flood breaketh out from the inhabitant; even the waters forgotten of the foot: they are dried up, they are gone away from men.", "ref": "Job 28:4"}, "5": {"text": "As for the earth, out of it cometh bread: and under it is turned up as it were fire.", "ref": "Job 28:5"}, "6": {"text": "The stones of it are the place of sapphires: and it hath dust of gold.", "ref": "Job 28:6"}, "7": {"text": "There is a path which no fowl knoweth, and which the vulture’s eye hath not seen:", "ref": "Job 28:7"}, "8": {"text": "The lion’s whelps have not trodden it, nor the fierce lion passed by it.", "ref": "Job 28:8"}, "9": {"text": "He putteth forth his hand upon the rock; he overturneth the mountains by the roots.", "ref": "Job 28:9"}, "10": {"text": "He cutteth out rivers among the rocks; and his eye seeth every precious thing.", "ref": "Job 28:10"}, "11": {"text": "He bindeth the floods from overflowing; and the thing that is hid bringeth he forth to light.", "ref": "Job 28:11"}, "12": {"text": "But where shall wisdom be found? and where is the place of understanding?", "ref": "Job 28:12"}, "13": {"text": "Man knoweth not the price thereof; neither is it found in the land of the living.", "ref": "Job 28:13"}, "14": {"text": "The depth saith, It is not in me: and the sea saith, It is not with me.", "ref": "Job 28:14"}, "15": {"text": "It cannot be gotten for gold, neither shall silver be weighed for the price thereof.", "ref": "Job 28:15"}, "16": {"text": "It cannot be valued with the gold of Ophir, with the precious onyx, or the sapphire.", "ref": "Job 28:16"}, "17": {"text": "The gold and the crystal cannot equal it: and the exchange of it shall not be for jewels of fine gold.", "ref": "Job 28:17"}, "18": {"text": "No mention shall be made of coral, or of pearls: for the price of wisdom is above rubies.", "ref": "Job 28:18"}, "19": {"text": "The topaz of Ethiopia shall not equal it, neither shall it be valued with pure gold.", "ref": "Job 28:19"}, "20": {"text": "Whence then cometh wisdom? and where is the place of understanding?", "ref": "Job 28:20"}, "21": {"text": "Seeing it is hid from the eyes of all living, and kept close from the fowls of the air.", "ref": "Job 28:21"}, "22": {"text": "Destruction and death say, We have heard the fame thereof with our ears.", "ref": "Job 28:22"}, "23": {"text": "God understandeth the way thereof, and he knoweth the place thereof.", "ref": "Job 28:23"}, "24": {"text": "For he looketh to the ends of the earth, and seeth under the whole heaven;", "ref": "Job 28:24"}, "25": {"text": "To make the weight for the winds; and he weigheth the waters by measure.", "ref": "Job 28:25"}, "26": {"text": "When he made a decree for the rain, and a way for the lightning of the thunder:", "ref": "Job 28:26"}, "27": {"text": "Then did he see it, and declare it; he prepared it, yea, and searched it out.", "ref": "Job 28:27"}, "28": {"text": "And unto man he said, Behold, the fear of the LORD, that is wisdom; and to depart from evil is understanding.", "ref": "Job 28:28"}}}, "29": {"chapter": "29", "title": "Job 29", "verses": {"1": {"text": "Moreover Job continued his parable, and said,", "ref": "Job 29:1"}, "2": {"text": "Oh that I were as in months past, as in the days when God preserved me;", "ref": "Job 29:2"}, "3": {"text": "When his candle shined upon my head, and when by his light I walked through darkness;", "ref": "Job 29:3"}, "4": {"text": "As I was in the days of my youth, when the secret of God was upon my tabernacle;", "ref": "Job 29:4"}, "5": {"text": "When the Almighty was yet with me, when my children were about me;", "ref": "Job 29:5"}, "6": {"text": "When I washed my steps with butter, and the rock poured me out rivers of oil;", "ref": "Job 29:6"}, "7": {"text": "When I went out to the gate through the city, when I prepared my seat in the street!", "ref": "Job 29:7"}, "8": {"text": "The young men saw me, and hid themselves: and the aged arose, and stood up.", "ref": "Job 29:8"}, "9": {"text": "The princes refrained talking, and laid their hand on their mouth.", "ref": "Job 29:9"}, "10": {"text": "The nobles held their peace, and their tongue cleaved to the roof of their mouth.", "ref": "Job 29:10"}, "11": {"text": "When the ear heard me, then it blessed me; and when the eye saw me, it gave witness to me:", "ref": "Job 29:11"}, "12": {"text": "Because I delivered the poor that cried, and the fatherless, and him that had none to help him.", "ref": "Job 29:12"}, "13": {"text": "The blessing of him that was ready to perish came upon me: and I caused the widow’s heart to sing for joy.", "ref": "Job 29:13"}, "14": {"text": "I put on righteousness, and it clothed me: my judgment was as a robe and a diadem.", "ref": "Job 29:14"}, "15": {"text": "I was eyes to the blind, and feet was I to the lame.", "ref": "Job 29:15"}, "16": {"text": "I was a father to the poor: and the cause which I knew not I searched out.", "ref": "Job 29:16"}, "17": {"text": "And I brake the jaws of the wicked, and plucked the spoil out of his teeth.", "ref": "Job 29:17"}, "18": {"text": "Then I said, I shall die in my nest, and I shall multiply my days as the sand.", "ref": "Job 29:18"}, "19": {"text": "My root was spread out by the waters, and the dew lay all night upon my branch.", "ref": "Job 29:19"}, "20": {"text": "My glory was fresh in me, and my bow was renewed in my hand.", "ref": "Job 29:20"}, "21": {"text": "Unto me men gave ear, and waited, and kept silence at my counsel.", "ref": "Job 29:21"}, "22": {"text": "After my words they spake not again; and my speech dropped upon them.", "ref": "Job 29:22"}, "23": {"text": "And they waited for me as for the rain; and they opened their mouth wide as for the latter rain.", "ref": "Job 29:23"}, "24": {"text": "If I laughed on them, they believed it not; and the light of my countenance they cast not down.", "ref": "Job 29:24"}, "25": {"text": "I chose out their way, and sat chief, and dwelt as a king in the army, as one that comforteth the mourners.", "ref": "Job 29:25"}}}, "30": {"chapter": "30", "title": "Job 30", "verses": {"1": {"text": "But now they that are younger than I have me in derision, whose fathers I would have disdained to have set with the dogs of my flock.", "ref": "Job 30:1"}, "2": {"text": "Yea, whereto might the strength of their hands profit me, in whom old age was perished?", "ref": "Job 30:2"}, "3": {"text": "For want and famine they were solitary; fleeing into the wilderness in former time desolate and waste.", "ref": "Job 30:3"}, "4": {"text": "Who cut up mallows by the bushes, and juniper roots for their meat.", "ref": "Job 30:4"}, "5": {"text": "They were driven forth from among men, (they cried after them as after a thief;)", "ref": "Job 30:5"}, "6": {"text": "To dwell in the cliffs of the valleys, in caves of the earth, and in the rocks.", "ref": "Job 30:6"}, "7": {"text": "Among the bushes they brayed; under the nettles they were gathered together.", "ref": "Job 30:7"}, "8": {"text": "They were children of fools, yea, children of base men: they were viler than the earth.", "ref": "Job 30:8"}, "9": {"text": "And now am I their song, yea, I am their byword.", "ref": "Job 30:9"}, "10": {"text": "They abhor me, they flee far from me, and spare not to spit in my face.", "ref": "Job 30:10"}, "11": {"text": "Because he hath loosed my cord, and afflicted me, they have also let loose the bridle before me.", "ref": "Job 30:11"}, "12": {"text": "Upon my right hand rise the youth; they push away my feet, and they raise up against me the ways of their destruction.", "ref": "Job 30:12"}, "13": {"text": "They mar my path, they set forward my calamity, they have no helper.", "ref": "Job 30:13"}, "14": {"text": "They came upon me as a wide breaking in of waters: in the desolation they rolled themselves upon me.", "ref": "Job 30:14"}, "15": {"text": "Terrors are turned upon me: they pursue my soul as the wind: and my welfare passeth away as a cloud.", "ref": "Job 30:15"}, "16": {"text": "And now my soul is poured out upon me; the days of affliction have taken hold upon me.", "ref": "Job 30:16"}, "17": {"text": "My bones are pierced in me in the night season: and my sinews take no rest.", "ref": "Job 30:17"}, "18": {"text": "By the great force of my disease is my garment changed: it bindeth me about as the collar of my coat.", "ref": "Job 30:18"}, "19": {"text": "He hath cast me into the mire, and I am become like dust and ashes.", "ref": "Job 30:19"}, "20": {"text": "I cry unto thee, and thou dost not hear me: I stand up, and thou regardest me not.", "ref": "Job 30:20"}, "21": {"text": "Thou art become cruel to me: with thy strong hand thou opposest thyself against me.", "ref": "Job 30:21"}, "22": {"text": "Thou liftest me up to the wind; thou causest me to ride upon it, and dissolvest my substance.", "ref": "Job 30:22"}, "23": {"text": "For I know that thou wilt bring me to death, and to the house appointed for all living.", "ref": "Job 30:23"}, "24": {"text": "Howbeit he will not stretch out his hand to the grave, though they cry in his destruction.", "ref": "Job 30:24"}, "25": {"text": "Did not I weep for him that was in trouble? was not my soul grieved for the poor?", "ref": "Job 30:25"}, "26": {"text": "When I looked for good, then evil came unto me: and when I waited for light, there came darkness.", "ref": "Job 30:26"}, "27": {"text": "My bowels boiled, and rested not: the days of affliction prevented me.", "ref": "Job 30:27"}, "28": {"text": "I went mourning without the sun: I stood up, and I cried in the congregation.", "ref": "Job 30:28"}, "29": {"text": "I am a brother to dragons, and a companion to owls.", "ref": "Job 30:29"}, "30": {"text": "My skin is black upon me, and my bones are burned with heat.", "ref": "Job 30:30"}, "31": {"text": "My harp also is turned to mourning, and my organ into the voice of them that weep.", "ref": "Job 30:31"}}}, "31": {"chapter": "31", "title": "Job 31", "verses": {"1": {"text": "I made a covenant with mine eyes; why then should I think upon a maid?", "ref": "Job 31:1"}, "2": {"text": "For what portion of God is there from above? and what inheritance of the Almighty from on high?", "ref": "Job 31:2"}, "3": {"text": "Is not destruction to the wicked? and a strange punishment to the workers of iniquity?", "ref": "Job 31:3"}, "4": {"text": "Doth not he see my ways, and count all my steps?", "ref": "Job 31:4"}, "5": {"text": "If I have walked with vanity, or if my foot hath hasted to deceit;", "ref": "Job 31:5"}, "6": {"text": "Let me be weighed in an even balance that God may know mine integrity.", "ref": "Job 31:6"}, "7": {"text": "If my step hath turned out of the way, and mine heart walked after mine eyes, and if any blot hath cleaved to mine hands;", "ref": "Job 31:7"}, "8": {"text": "Then let me sow, and let another eat; yea, let my offspring be rooted out.", "ref": "Job 31:8"}, "9": {"text": "If mine heart have been deceived by a woman, or if I have laid wait at my neighbour’s door;", "ref": "Job 31:9"}, "10": {"text": "Then let my wife grind unto another, and let others bow down upon her.", "ref": "Job 31:10"}, "11": {"text": "For this is an heinous crime; yea, it is an iniquity to be punished by the judges.", "ref": "Job 31:11"}, "12": {"text": "For it is a fire that consumeth to destruction, and would root out all mine increase.", "ref": "Job 31:12"}, "13": {"text": "If I did despise the cause of my manservant or of my maidservant, when they contended with me;", "ref": "Job 31:13"}, "14": {"text": "What then shall I do when God riseth up? and when he visiteth, what shall I answer him?", "ref": "Job 31:14"}, "15": {"text": "Did not he that made me in the womb make him? and did not one fashion us in the womb?", "ref": "Job 31:15"}, "16": {"text": "If I have withheld the poor from their desire, or have caused the eyes of the widow to fail;", "ref": "Job 31:16"}, "17": {"text": "Or have eaten my morsel myself alone, and the fatherless hath not eaten thereof;", "ref": "Job 31:17"}, "18": {"text": "(For from my youth he was brought up with me, as with a father, and I have guided her from my mother’s womb;)", "ref": "Job 31:18"}, "19": {"text": "If I have seen any perish for want of clothing, or any poor without covering;", "ref": "Job 31:19"}, "20": {"text": "If his loins have not blessed me, and if he were not warmed with the fleece of my sheep;", "ref": "Job 31:20"}, "21": {"text": "If I have lifted up my hand against the fatherless, when I saw my help in the gate:", "ref": "Job 31:21"}, "22": {"text": "Then let mine arm fall from my shoulder blade, and mine arm be broken from the bone.", "ref": "Job 31:22"}, "23": {"text": "For destruction from God was a terror to me, and by reason of his highness I could not endure.", "ref": "Job 31:23"}, "24": {"text": "If I have made gold my hope, or have said to the fine gold, Thou art my confidence;", "ref": "Job 31:24"}, "25": {"text": "If I rejoiced because my wealth was great, and because mine hand had gotten much;", "ref": "Job 31:25"}, "26": {"text": "If I beheld the sun when it shined, or the moon walking in brightness;", "ref": "Job 31:26"}, "27": {"text": "And my heart hath been secretly enticed, or my mouth hath kissed my hand:", "ref": "Job 31:27"}, "28": {"text": "This also were an iniquity to be punished by the judge: for I should have denied the God that is above.", "ref": "Job 31:28"}, "29": {"text": "If I rejoiced at the destruction of him that hated me, or lifted up myself when evil found him:", "ref": "Job 31:29"}, "30": {"text": "Neither have I suffered my mouth to sin by wishing a curse to his soul.", "ref": "Job 31:30"}, "31": {"text": "If the men of my tabernacle said not, Oh that we had of his flesh! we cannot be satisfied.", "ref": "Job 31:31"}, "32": {"text": "The stranger did not lodge in the street: but I opened my doors to the traveller.", "ref": "Job 31:32"}, "33": {"text": "If I covered my transgressions as Adam, by hiding mine iniquity in my bosom:", "ref": "Job 31:33"}, "34": {"text": "Did I fear a great multitude, or did the contempt of families terrify me, that I kept silence, and went not out of the door?", "ref": "Job 31:34"}, "35": {"text": "Oh that one would hear me! behold, my desire is, that the Almighty would answer me, and that mine adversary had written a book.", "ref": "Job 31:35"}, "36": {"text": "Surely I would take it upon my shoulder, and bind it as a crown to me.", "ref": "Job 31:36"}, "37": {"text": "I would declare unto him the number of my steps; as a prince would I go near unto him.", "ref": "Job 31:37"}, "38": {"text": "If my land cry against me, or that the furrows likewise thereof complain;", "ref": "Job 31:38"}, "39": {"text": "If I have eaten the fruits thereof without money, or have caused the owners thereof to lose their life:", "ref": "Job 31:39"}, "40": {"text": "Let thistles grow instead of wheat, and cockle instead of barley. The words of Job are ended.", "ref": "Job 31:40"}}}, "32": {"chapter": "32", "title": "Job 32", "verses": {"1": {"text": "So these three men ceased to answer Job, because he was righteous in his own eyes.", "ref": "Job 32:1"}, "2": {"text": "Then was kindled the wrath of Elihu the son of Barachel the Buzite, of the kindred of Ram: against Job was his wrath kindled, because he justified himself rather than God.", "ref": "Job 32:2"}, "3": {"text": "Also against his three friends was his wrath kindled, because they had found no answer, and yet had condemned Job.", "ref": "Job 32:3"}, "4": {"text": "Now Elihu had waited till Job had spoken, because they were elder than he.", "ref": "Job 32:4"}, "5": {"text": "When Elihu saw that there was no answer in the mouth of these three men, then his wrath was kindled.", "ref": "Job 32:5"}, "6": {"text": "And Elihu the son of Barachel the Buzite answered and said, I am young, and ye are very old; wherefore I was afraid, and durst not shew you mine opinion.", "ref": "Job 32:6"}, "7": {"text": "I said, Days should speak, and multitude of years should teach wisdom.", "ref": "Job 32:7"}, "8": {"text": "But there is a spirit in man: and the inspiration of the Almighty giveth them understanding.", "ref": "Job 32:8"}, "9": {"text": "Great men are not always wise: neither do the aged understand judgment.", "ref": "Job 32:9"}, "10": {"text": "Therefore I said, Hearken to me; I also will shew mine opinion.", "ref": "Job 32:10"}, "11": {"text": "Behold, I waited for your words; I gave ear to your reasons, whilst ye searched out what to say.", "ref": "Job 32:11"}, "12": {"text": "Yea, I attended unto you, and, behold, there was none of you that convinced Job, or that answered his words:", "ref": "Job 32:12"}, "13": {"text": "Lest ye should say, We have found out wisdom: God thrusteth him down, not man.", "ref": "Job 32:13"}, "14": {"text": "Now he hath not directed his words against me: neither will I answer him with your speeches.", "ref": "Job 32:14"}, "15": {"text": "They were amazed, they answered no more: they left off speaking.", "ref": "Job 32:15"}, "16": {"text": "When I had waited, (for they spake not, but stood still, and answered no more;)", "ref": "Job 32:16"}, "17": {"text": "I said, I will answer also my part, I also will shew mine opinion.", "ref": "Job 32:17"}, "18": {"text": "For I am full of matter, the spirit within me constraineth me.", "ref": "Job 32:18"}, "19": {"text": "Behold, my belly is as wine which hath no vent; it is ready to burst like new bottles.", "ref": "Job 32:19"}, "20": {"text": "I will speak, that I may be refreshed: I will open my lips and answer.", "ref": "Job 32:20"}, "21": {"text": "Let me not, I pray you, accept any man’s person, neither let me give flattering titles unto man.", "ref": "Job 32:21"}, "22": {"text": "For I know not to give flattering titles; in so doing my maker would soon take me away.", "ref": "Job 32:22"}}}, "33": {"chapter": "33", "title": "Job 33", "verses": {"1": {"text": "Wherefore, Job, I pray thee, hear my speeches, and hearken to all my words.", "ref": "Job 33:1"}, "2": {"text": "Behold, now I have opened my mouth, my tongue hath spoken in my mouth.", "ref": "Job 33:2"}, "3": {"text": "My words shall be of the uprightness of my heart: and my lips shall utter knowledge clearly.", "ref": "Job 33:3"}, "4": {"text": "The spirit of God hath made me, and the breath of the Almighty hath given me life.", "ref": "Job 33:4"}, "5": {"text": "If thou canst answer me, set thy words in order before me, stand up.", "ref": "Job 33:5"}, "6": {"text": "Behold, I am according to thy wish in God’s stead: I also am formed out of the clay.", "ref": "Job 33:6"}, "7": {"text": "Behold, my terror shall not make thee afraid, neither shall my hand be heavy upon thee.", "ref": "Job 33:7"}, "8": {"text": "Surely thou hast spoken in mine hearing, and I have heard the voice of thy words, saying,", "ref": "Job 33:8"}, "9": {"text": "I am clean without transgression, I am innocent; neither is there iniquity in me.", "ref": "Job 33:9"}, "10": {"text": "Behold, he findeth occasions against me, he counteth me for his enemy,", "ref": "Job 33:10"}, "11": {"text": "He putteth my feet in the stocks, he marketh all my paths.", "ref": "Job 33:11"}, "12": {"text": "Behold, in this thou art not just: I will answer thee, that God is greater than man.", "ref": "Job 33:12"}, "13": {"text": "Why dost thou strive against him? for he giveth not account of any of his matters.", "ref": "Job 33:13"}, "14": {"text": "For God speaketh once, yea twice, yet man perceiveth it not.", "ref": "Job 33:14"}, "15": {"text": "In a dream, in a vision of the night, when deep sleep falleth upon men, in slumberings upon the bed;", "ref": "Job 33:15"}, "16": {"text": "Then he openeth the ears of men, and sealeth their instruction,", "ref": "Job 33:16"}, "17": {"text": "That he may withdraw man from his purpose, and hide pride from man.", "ref": "Job 33:17"}, "18": {"text": "He keepeth back his soul from the pit, and his life from perishing by the sword.", "ref": "Job 33:18"}, "19": {"text": "He is chastened also with pain upon his bed, and the multitude of his bones with strong pain:", "ref": "Job 33:19"}, "20": {"text": "So that his life abhorreth bread, and his soul dainty meat.", "ref": "Job 33:20"}, "21": {"text": "His flesh is consumed away, that it cannot be seen; and his bones that were not seen stick out.", "ref": "Job 33:21"}, "22": {"text": "Yea, his soul draweth near unto the grave, and his life to the destroyers.", "ref": "Job 33:22"}, "23": {"text": "If there be a messenger with him, an interpreter, one among a thousand, to shew unto man his uprightness:", "ref": "Job 33:23"}, "24": {"text": "Then he is gracious unto him, and saith, Deliver him from going down to the pit: I have found a ransom.", "ref": "Job 33:24"}, "25": {"text": "His flesh shall be fresher than a child’s: he shall return to the days of his youth:", "ref": "Job 33:25"}, "26": {"text": "He shall pray unto God, and he will be favourable unto him: and he shall see his face with joy: for he will render unto man his righteousness.", "ref": "Job 33:26"}, "27": {"text": "He looketh upon men, and if any say, I have sinned, and perverted that which was right, and it profited me not;", "ref": "Job 33:27"}, "28": {"text": "He will deliver his soul from going into the pit, and his life shall see the light.", "ref": "Job 33:28"}, "29": {"text": "Lo, all these things worketh God oftentimes with man,", "ref": "Job 33:29"}, "30": {"text": "To bring back his soul from the pit, to be enlightened with the light of the living.", "ref": "Job 33:30"}, "31": {"text": "Mark well, O Job, hearken unto me: hold thy peace, and I will speak.", "ref": "Job 33:31"}, "32": {"text": "If thou hast anything to say, answer me: speak, for I desire to justify thee.", "ref": "Job 33:32"}, "33": {"text": "If not, hearken unto me: hold thy peace, and I shall teach thee wisdom.", "ref": "Job 33:33"}}}, "34": {"chapter": "34", "title": "Job 34", "verses": {"1": {"text": "Furthermore Elihu answered and said,", "ref": "Job 34:1"}, "2": {"text": "Hear my words, O ye wise men; and give ear unto me, ye that have knowledge.", "ref": "Job 34:2"}, "3": {"text": "For the ear trieth words, as the mouth tasteth meat.", "ref": "Job 34:3"}, "4": {"text": "Let us choose to us judgment: let us know among ourselves what is good.", "ref": "Job 34:4"}, "5": {"text": "For Job hath said, I am righteous: and God hath taken away my judgment.", "ref": "Job 34:5"}, "6": {"text": "Should I lie against my right? my wound is incurable without transgression.", "ref": "Job 34:6"}, "7": {"text": "What man is like Job, who drinketh up scorning like water?", "ref": "Job 34:7"}, "8": {"text": "Which goeth in company with the workers of iniquity, and walketh with wicked men.", "ref": "Job 34:8"}, "9": {"text": "For he hath said, It profiteth a man nothing that he should delight himself with God.", "ref": "Job 34:9"}, "10": {"text": "Therefore hearken unto me ye men of understanding: far be it from God, that he should do wickedness; and from the Almighty, that he should commit iniquity.", "ref": "Job 34:10"}, "11": {"text": "For the work of a man shall he render unto him, and cause every man to find according to his ways.", "ref": "Job 34:11"}, "12": {"text": "Yea, surely God will not do wickedly, neither will the Almighty pervert judgment.", "ref": "Job 34:12"}, "13": {"text": "Who hath given him a charge over the earth? or who hath disposed the whole world?", "ref": "Job 34:13"}, "14": {"text": "If he set his heart upon man, if he gather unto himself his spirit and his breath;", "ref": "Job 34:14"}, "15": {"text": "All flesh shall perish together, and man shall turn again unto dust.", "ref": "Job 34:15"}, "16": {"text": "If now thou hast understanding, hear this: hearken to the voice of my words.", "ref": "Job 34:16"}, "17": {"text": "Shall even he that hateth right govern? and wilt thou condemn him that is most just?", "ref": "Job 34:17"}, "18": {"text": "Is it fit to say to a king, Thou art wicked? and to princes, Ye are ungodly?", "ref": "Job 34:18"}, "19": {"text": "How much less to him that accepteth not the persons of princes, nor regardeth the rich more than the poor? for they all are the work of his hands.", "ref": "Job 34:19"}, "20": {"text": "In a moment shall they die, and the people shall be troubled at midnight, and pass away: and the mighty shall be taken away without hand.", "ref": "Job 34:20"}, "21": {"text": "For his eyes are upon the ways of man, and he seeth all his goings.", "ref": "Job 34:21"}, "22": {"text": "There is no darkness, nor shadow of death, where the workers of iniquity may hide themselves.", "ref": "Job 34:22"}, "23": {"text": "For he will not lay upon man more than right; that he should enter into judgment with God.", "ref": "Job 34:23"}, "24": {"text": "He shall break in pieces mighty men without number, and set others in their stead.", "ref": "Job 34:24"}, "25": {"text": "Therefore he knoweth their works, and he overturneth them in the night, so that they are destroyed.", "ref": "Job 34:25"}, "26": {"text": "He striketh them as wicked men in the open sight of others;", "ref": "Job 34:26"}, "27": {"text": "Because they turned back from him, and would not consider any of his ways:", "ref": "Job 34:27"}, "28": {"text": "So that they cause the cry of the poor to come unto him, and he heareth the cry of the afflicted.", "ref": "Job 34:28"}, "29": {"text": "When he giveth quietness, who then can make trouble? and when he hideth his face, who then can behold him? whether it be done against a nation, or against a man only:", "ref": "Job 34:29"}, "30": {"text": "That the hypocrite reign not, lest the people be ensnared.", "ref": "Job 34:30"}, "31": {"text": "Surely it is meet to be said unto God, I have borne chastisement, I will not offend any more:", "ref": "Job 34:31"}, "32": {"text": "That which I see not teach thou me: if I have done iniquity, I will do no more.", "ref": "Job 34:32"}, "33": {"text": "Should it be according to thy mind? he will recompense it, whether thou refuse, or whether thou choose; and not I: therefore speak what thou knowest.", "ref": "Job 34:33"}, "34": {"text": "Let men of understanding tell me, and let a wise man hearken unto me.", "ref": "Job 34:34"}, "35": {"text": "Job hath spoken without knowledge, and his words were without wisdom.", "ref": "Job 34:35"}, "36": {"text": "My desire is that Job may be tried unto the end because of his answers for wicked men.", "ref": "Job 34:36"}, "37": {"text": "For he addeth rebellion unto his sin, he clappeth his hands among us, and multiplieth his words against God.", "ref": "Job 34:37"}}}, "35": {"chapter": "35", "title": "Job 35", "verses": {"1": {"text": "Elihu spake moreover, and said,", "ref": "Job 35:1"}, "2": {"text": "Thinkest thou this to be right, that thou saidst, My righteousness is more than God’s?", "ref": "Job 35:2"}, "3": {"text": "For thou saidst, What advantage will it be unto thee? and, What profit shall I have, if I be cleansed from my sin?", "ref": "Job 35:3"}, "4": {"text": "I will answer thee, and thy companions with thee.", "ref": "Job 35:4"}, "5": {"text": "Look unto the heavens, and see; and behold the clouds which are higher than thou.", "ref": "Job 35:5"}, "6": {"text": "If thou sinnest, what doest thou against him? or if thy transgressions be multiplied, what doest thou unto him?", "ref": "Job 35:6"}, "7": {"text": "If thou be righteous, what givest thou him? or what receiveth he of thine hand?", "ref": "Job 35:7"}, "8": {"text": "Thy wickedness may hurt a man as thou art; and thy righteousness may profit the son of man.", "ref": "Job 35:8"}, "9": {"text": "By reason of the multitude of oppressions they make the oppressed to cry: they cry out by reason of the arm of the mighty.", "ref": "Job 35:9"}, "10": {"text": "But none saith, Where is God my maker, who giveth songs in the night;", "ref": "Job 35:10"}, "11": {"text": "Who teacheth us more than the beasts of the earth, and maketh us wiser than the fowls of heaven?", "ref": "Job 35:11"}, "12": {"text": "There they cry, but none giveth answer, because of the pride of evil men.", "ref": "Job 35:12"}, "13": {"text": "Surely God will not hear vanity, neither will the Almighty regard it.", "ref": "Job 35:13"}, "14": {"text": "Although thou sayest thou shalt not see him, yet judgment is before him; therefore trust thou in him.", "ref": "Job 35:14"}, "15": {"text": "But now, because it is not so, he hath visited in his anger; yet he knoweth it not in great extremity:", "ref": "Job 35:15"}, "16": {"text": "Therefore doth Job open his mouth in vain; he multiplieth words without knowledge.", "ref": "Job 35:16"}}}, "36": {"chapter": "36", "title": "Job 36", "verses": {"1": {"text": "Elihu also proceeded, and said,", "ref": "Job 36:1"}, "2": {"text": "Suffer me a little, and I will shew thee that I have yet to speak on God’s behalf.", "ref": "Job 36:2"}, "3": {"text": "I will fetch my knowledge from afar, and will ascribe righteousness to my Maker.", "ref": "Job 36:3"}, "4": {"text": "For truly my words shall not be false: he that is perfect in knowledge is with thee.", "ref": "Job 36:4"}, "5": {"text": "Behold, God is mighty, and despiseth not any: he is mighty in strength and wisdom.", "ref": "Job 36:5"}, "6": {"text": "He preserveth not the life of the wicked: but giveth right to the poor.", "ref": "Job 36:6"}, "7": {"text": "He withdraweth not his eyes from the righteous: but with kings are they on the throne; yea, he doth establish them for ever, and they are exalted.", "ref": "Job 36:7"}, "8": {"text": "And if they be bound in fetters, and be holden in cords of affliction;", "ref": "Job 36:8"}, "9": {"text": "Then he sheweth them their work, and their transgressions that they have exceeded.", "ref": "Job 36:9"}, "10": {"text": "He openeth also their ear to discipline, and commandeth that they return from iniquity.", "ref": "Job 36:10"}, "11": {"text": "If they obey and serve him, they shall spend their days in prosperity, and their years in pleasures.", "ref": "Job 36:11"}, "12": {"text": "But if they obey not, they shall perish by the sword, and they shall die without knowledge.", "ref": "Job 36:12"}, "13": {"text": "But the hypocrites in heart heap up wrath: they cry not when he bindeth them.", "ref": "Job 36:13"}, "14": {"text": "They die in youth, and their life is among the unclean.", "ref": "Job 36:14"}, "15": {"text": "He delivereth the poor in his affliction, and openeth their ears in oppression.", "ref": "Job 36:15"}, "16": {"text": "Even so would he have removed thee out of the strait into a broad place, where there is no straitness; and that which should be set on thy table should be full of fatness.", "ref": "Job 36:16"}, "17": {"text": "But thou hast fulfilled the judgment of the wicked: judgment and justice take hold on thee.", "ref": "Job 36:17"}, "18": {"text": "Because there is wrath, beware lest he take thee away with his stroke: then a great ransom cannot deliver thee.", "ref": "Job 36:18"}, "19": {"text": "Will he esteem thy riches? no, not gold, nor all the forces of strength.", "ref": "Job 36:19"}, "20": {"text": "Desire not the night, when people are cut off in their place.", "ref": "Job 36:20"}, "21": {"text": "Take heed, regard not iniquity: for this hast thou chosen rather than affliction.", "ref": "Job 36:21"}, "22": {"text": "Behold, God exalteth by his power: who teacheth like him?", "ref": "Job 36:22"}, "23": {"text": "Who hath enjoined him his way? or who can say, Thou hast wrought iniquity?", "ref": "Job 36:23"}, "24": {"text": "Remember that thou magnify his work, which men behold.", "ref": "Job 36:24"}, "25": {"text": "Every man may see it; man may behold it afar off.", "ref": "Job 36:25"}, "26": {"text": "Behold, God is great, and we know him not, neither can the number of his years be searched out.", "ref": "Job 36:26"}, "27": {"text": "For he maketh small the drops of water: they pour down rain according to the vapour thereof:", "ref": "Job 36:27"}, "28": {"text": "Which the clouds do drop and distil upon man abundantly.", "ref": "Job 36:28"}, "29": {"text": "Also can any understand the spreadings of the clouds, or the noise of his tabernacle?", "ref": "Job 36:29"}, "30": {"text": "Behold, he spreadeth his light upon it, and covereth the bottom of the sea.", "ref": "Job 36:30"}, "31": {"text": "For by them judgeth he the people; he giveth meat in abundance.", "ref": "Job 36:31"}, "32": {"text": "With clouds he covereth the light; and commandeth it not to shine by the cloud that cometh betwixt.", "ref": "Job 36:32"}, "33": {"text": "The noise thereof sheweth concerning it, the cattle also concerning the vapour.", "ref": "Job 36:33"}}}, "37": {"chapter": "37", "title": "Job 37", "verses": {"1": {"text": "At this also my heart trembleth, and is moved out of his place.", "ref": "Job 37:1"}, "2": {"text": "Hear attentively the noise of his voice, and the sound that goeth out of his mouth.", "ref": "Job 37:2"}, "3": {"text": "He directeth it under the whole heaven, and his lightning unto the ends of the earth.", "ref": "Job 37:3"}, "4": {"text": "After it a voice roareth: he thundereth with the voice of his excellency; and he will not stay them when his voice is heard.", "ref": "Job 37:4"}, "5": {"text": "God thundereth marvellously with his voice; great things doeth he, which we cannot comprehend.", "ref": "Job 37:5"}, "6": {"text": "For he saith to the snow, Be thou on the earth; likewise to the small rain, and to the great rain of his strength.", "ref": "Job 37:6"}, "7": {"text": "He sealeth up the hand of every man; that all men may know his work.", "ref": "Job 37:7"}, "8": {"text": "Then the beasts go into dens, and remain in their places.", "ref": "Job 37:8"}, "9": {"text": "Out of the south cometh the whirlwind: and cold out of the north.", "ref": "Job 37:9"}, "10": {"text": "By the breath of God frost is given: and the breadth of the waters is straitened.", "ref": "Job 37:10"}, "11": {"text": "Also by watering he wearieth the thick cloud: he scattereth his bright cloud:", "ref": "Job 37:11"}, "12": {"text": "And it is turned round about by his counsels: that they may do whatsoever he commandeth them upon the face of the world in the earth.", "ref": "Job 37:12"}, "13": {"text": "He causeth it to come, whether for correction, or for his land, or for mercy.", "ref": "Job 37:13"}, "14": {"text": "Hearken unto this, O Job: stand still, and consider the wondrous works of God.", "ref": "Job 37:14"}, "15": {"text": "Dost thou know when God disposed them, and caused the light of his cloud to shine?", "ref": "Job 37:15"}, "16": {"text": "Dost thou know the balancings of the clouds, the wondrous works of him which is perfect in knowledge?", "ref": "Job 37:16"}, "17": {"text": "How thy garments are warm, when he quieteth the earth by the south wind?", "ref": "Job 37:17"}, "18": {"text": "Hast thou with him spread out the sky, which is strong, and as a molten looking glass?", "ref": "Job 37:18"}, "19": {"text": "Teach us what we shall say unto him; for we cannot order our speech by reason of darkness.", "ref": "Job 37:19"}, "20": {"text": "Shall it be told him that I speak? if a man speak, surely he shall be swallowed up.", "ref": "Job 37:20"}, "21": {"text": "And now men see not the bright light which is in the clouds: but the wind passeth, and cleanseth them.", "ref": "Job 37:21"}, "22": {"text": "Fair weather cometh out of the north: with God is terrible majesty.", "ref": "Job 37:22"}, "23": {"text": "Touching the Almighty, we cannot find him out: he is excellent in power, and in judgment, and in plenty of justice: he will not afflict.", "ref": "Job 37:23"}, "24": {"text": "Men do therefore fear him: he respecteth not any that are wise of heart.", "ref": "Job 37:24"}}}, "38": {"chapter": "38", "title": "Job 38", "verses": {"1": {"text": "Then the LORD answered Job out of the whirlwind, and said,", "ref": "Job 38:1"}, "2": {"text": "Who is this that darkeneth counsel by words without knowledge?", "ref": "Job 38:2"}, "3": {"text": "Gird up now thy loins like a man; for I will demand of thee, and answer thou me.", "ref": "Job 38:3"}, "4": {"text": "Where wast thou when I laid the foundations of the earth? declare, if thou hast understanding.", "ref": "Job 38:4"}, "5": {"text": "Who hath laid the measures thereof, if thou knowest? or who hath stretched the line upon it?", "ref": "Job 38:5"}, "6": {"text": "Whereupon are the foundations thereof fastened? or who laid the corner stone thereof;", "ref": "Job 38:6"}, "7": {"text": "When the morning stars sang together, and all the sons of God shouted for joy?", "ref": "Job 38:7"}, "8": {"text": "Or who shut up the sea with doors, when it brake forth, as if it had issued out of the womb?", "ref": "Job 38:8"}, "9": {"text": "When I made the cloud the garment thereof, and thick darkness a swaddlingband for it,", "ref": "Job 38:9"}, "10": {"text": "And brake up for it my decreed place, and set bars and doors,", "ref": "Job 38:10"}, "11": {"text": "And said, Hitherto shalt thou come, but no further: and here shall thy proud waves be stayed?", "ref": "Job 38:11"}, "12": {"text": "Hast thou commanded the morning since thy days; and caused the dayspring to know his place;", "ref": "Job 38:12"}, "13": {"text": "That it might take hold of the ends of the earth, that the wicked might be shaken out of it?", "ref": "Job 38:13"}, "14": {"text": "It is turned as clay to the seal; and they stand as a garment.", "ref": "Job 38:14"}, "15": {"text": "And from the wicked their light is withholden, and the high arm shall be broken.", "ref": "Job 38:15"}, "16": {"text": "Hast thou entered into the springs of the sea? or hast thou walked in the search of the depth?", "ref": "Job 38:16"}, "17": {"text": "Have the gates of death been opened unto thee? or hast thou seen the doors of the shadow of death?", "ref": "Job 38:17"}, "18": {"text": "Hast thou perceived the breadth of the earth? declare if thou knowest it all.", "ref": "Job 38:18"}, "19": {"text": "Where is the way where light dwelleth? and as for darkness, where is the place thereof,", "ref": "Job 38:19"}, "20": {"text": "That thou shouldest take it to the bound thereof, and that thou shouldest know the paths to the house thereof?", "ref": "Job 38:20"}, "21": {"text": "Knowest thou it, because thou wast then born? or because the number of thy days is great?", "ref": "Job 38:21"}, "22": {"text": "Hast thou entered into the treasures of the snow? or hast thou seen the treasures of the hail,", "ref": "Job 38:22"}, "23": {"text": "Which I have reserved against the time of trouble, against the day of battle and war?", "ref": "Job 38:23"}, "24": {"text": "By what way is the light parted, which scattereth the east wind upon the earth?", "ref": "Job 38:24"}, "25": {"text": "Who hath divided a watercourse for the overflowing of waters, or a way for the lightning of thunder;", "ref": "Job 38:25"}, "26": {"text": "To cause it to rain on the earth, where no man is; on the wilderness, wherein there is no man;", "ref": "Job 38:26"}, "27": {"text": "To satisfy the desolate and waste ground; and to cause the bud of the tender herb to spring forth?", "ref": "Job 38:27"}, "28": {"text": "Hath the rain a father? or who hath begotten the drops of dew?", "ref": "Job 38:28"}, "29": {"text": "Out of whose womb came the ice? and the hoary frost of heaven, who hath gendered it?", "ref": "Job 38:29"}, "30": {"text": "The waters are hid as with a stone, and the face of the deep is frozen.", "ref": "Job 38:30"}, "31": {"text": "Canst thou bind the sweet influences of Pleiades, or loose the bands of Orion?", "ref": "Job 38:31"}, "32": {"text": "Canst thou bring forth Mazzaroth in his season? or canst thou guide Arcturus with his sons?", "ref": "Job 38:32"}, "33": {"text": "Knowest thou the ordinances of heaven? canst thou set the dominion thereof in the earth?", "ref": "Job 38:33"}, "34": {"text": "Canst thou lift up thy voice to the clouds, that abundance of waters may cover thee?", "ref": "Job 38:34"}, "35": {"text": "Canst thou send lightnings, that they may go, and say unto thee, Here we are?", "ref": "Job 38:35"}, "36": {"text": "Who hath put wisdom in the inward parts? or who hath given understanding to the heart?", "ref": "Job 38:36"}, "37": {"text": "Who can number the clouds in wisdom? or who can stay the bottles of heaven,", "ref": "Job 38:37"}, "38": {"text": "When the dust groweth into hardness, and the clods cleave fast together?", "ref": "Job 38:38"}, "39": {"text": "Wilt thou hunt the prey for the lion? or fill the appetite of the young lions,", "ref": "Job 38:39"}, "40": {"text": "When they couch in their dens, and abide in the covert to lie in wait?", "ref": "Job 38:40"}, "41": {"text": "Who provideth for the raven his food? when his young ones cry unto God, they wander for lack of meat.", "ref": "Job 38:41"}}}, "39": {"chapter": "39", "title": "Job 39", "verses": {"1": {"text": "Knowest thou the time when the wild goats of the rock bring forth? or canst thou mark when the hinds do calve?", "ref": "Job 39:1"}, "2": {"text": "Canst thou number the months that they fulfil? or knowest thou the time when they bring forth?", "ref": "Job 39:2"}, "3": {"text": "They bow themselves, they bring forth their young ones, they cast out their sorrows.", "ref": "Job 39:3"}, "4": {"text": "Their young ones are in good liking, they grow up with corn; they go forth, and return not unto them.", "ref": "Job 39:4"}, "5": {"text": "Who hath sent out the wild ass free? or who hath loosed the bands of the wild ass?", "ref": "Job 39:5"}, "6": {"text": "Whose house I have made the wilderness, and the barren land his dwellings.", "ref": "Job 39:6"}, "7": {"text": "He scorneth the multitude of the city, neither regardeth he the crying of the driver.", "ref": "Job 39:7"}, "8": {"text": "The range of the mountains is his pasture, and he searcheth after every green thing.", "ref": "Job 39:8"}, "9": {"text": "Will the unicorn be willing to serve thee, or abide by thy crib?", "ref": "Job 39:9"}, "10": {"text": "Canst thou bind the unicorn with his band in the furrow? or will he harrow the valleys after thee?", "ref": "Job 39:10"}, "11": {"text": "Wilt thou trust him, because his strength is great? or wilt thou leave thy labour to him?", "ref": "Job 39:11"}, "12": {"text": "Wilt thou believe him, that he will bring home thy seed, and gather it into thy barn?", "ref": "Job 39:12"}, "13": {"text": "Gavest thou the goodly wings unto the peacocks? or wings and feathers unto the ostrich?", "ref": "Job 39:13"}, "14": {"text": "Which leaveth her eggs in the earth, and warmeth them in dust,", "ref": "Job 39:14"}, "15": {"text": "And forgetteth that the foot may crush them, or that the wild beast may break them.", "ref": "Job 39:15"}, "16": {"text": "She is hardened against her young ones, as though they were not hers: her labour is in vain without fear;", "ref": "Job 39:16"}, "17": {"text": "Because God hath deprived her of wisdom, neither hath he imparted to her understanding.", "ref": "Job 39:17"}, "18": {"text": "What time she lifteth up herself on high, she scorneth the horse and his rider.", "ref": "Job 39:18"}, "19": {"text": "Hast thou given the horse strength? hast thou clothed his neck with thunder?", "ref": "Job 39:19"}, "20": {"text": "Canst thou make him afraid as a grasshopper? the glory of his nostrils is terrible.", "ref": "Job 39:20"}, "21": {"text": "He paweth in the valley, and rejoiceth in his strength: he goeth on to meet the armed men.", "ref": "Job 39:21"}, "22": {"text": "He mocketh at fear, and is not affrighted; neither turneth he back from the sword.", "ref": "Job 39:22"}, "23": {"text": "The quiver rattleth against him, the glittering spear and the shield.", "ref": "Job 39:23"}, "24": {"text": "He swalloweth the ground with fierceness and rage: neither believeth he that it is the sound of the trumpet.", "ref": "Job 39:24"}, "25": {"text": "He saith among the trumpets, Ha, ha; and he smelleth the battle afar off, the thunder of the captains, and the shouting.", "ref": "Job 39:25"}, "26": {"text": "Doth the hawk fly by thy wisdom, and stretch her wings toward the south?", "ref": "Job 39:26"}, "27": {"text": "Doth the eagle mount up at thy command, and make her nest on high?", "ref": "Job 39:27"}, "28": {"text": "She dwelleth and abideth on the rock, upon the crag of the rock, and the strong place.", "ref": "Job 39:28"}, "29": {"text": "From thence she seeketh the prey, and her eyes behold afar off.", "ref": "Job 39:29"}, "30": {"text": "Her young ones also suck up blood: and where the slain are, there is she.", "ref": "Job 39:30"}}}, "40": {"chapter": "40", "title": "Job 40", "verses": {"1": {"text": "Moreover the LORD answered Job, and said,", "ref": "Job 40:1"}, "2": {"text": "Shall he that contendeth with the Almighty instruct him? he that reproveth God, let him answer it.", "ref": "Job 40:2"}, "3": {"text": "Then Job answered the LORD, and said,", "ref": "Job 40:3"}, "4": {"text": "Behold, I am vile; what shall I answer thee? I will lay mine hand upon my mouth.", "ref": "Job 40:4"}, "5": {"text": "Once have I spoken; but I will not answer: yea, twice; but I will proceed no further.", "ref": "Job 40:5"}, "6": {"text": "Then answered the LORD unto Job out of the whirlwind, and said,", "ref": "Job 40:6"}, "7": {"text": "Gird up thy loins now like a man: I will demand of thee, and declare thou unto me.", "ref": "Job 40:7"}, "8": {"text": "Wilt thou also disannul my judgment? wilt thou condemn me, that thou mayest be righteous?", "ref": "Job 40:8"}, "9": {"text": "Hast thou an arm like God? or canst thou thunder with a voice like him?", "ref": "Job 40:9"}, "10": {"text": "Deck thyself now with majesty and excellency; and array thyself with glory and beauty.", "ref": "Job 40:10"}, "11": {"text": "Cast abroad the rage of thy wrath: and behold every one that is proud, and abase him.", "ref": "Job 40:11"}, "12": {"text": "Look on every one that is proud, and bring him low; and tread down the wicked in their place.", "ref": "Job 40:12"}, "13": {"text": "Hide them in the dust together; and bind their faces in secret.", "ref": "Job 40:13"}, "14": {"text": "Then will I also confess unto thee that thine own right hand can save thee.", "ref": "Job 40:14"}, "15": {"text": "Behold now behemoth, which I made with thee; he eateth grass as an ox.", "ref": "Job 40:15"}, "16": {"text": "Lo now, his strength is in his loins, and his force is in the navel of his belly.", "ref": "Job 40:16"}, "17": {"text": "He moveth his tail like a cedar: the sinews of his stones are wrapped together.", "ref": "Job 40:17"}, "18": {"text": "His bones are as strong pieces of brass; his bones are like bars of iron.", "ref": "Job 40:18"}, "19": {"text": "He is the chief of the ways of God: he that made him can make his sword to approach unto him.", "ref": "Job 40:19"}, "20": {"text": "Surely the mountains bring him forth food, where all the beasts of the field play.", "ref": "Job 40:20"}, "21": {"text": "He lieth under the shady trees, in the covert of the reed, and fens.", "ref": "Job 40:21"}, "22": {"text": "The shady trees cover him with their shadow; the willows of the brook compass him about.", "ref": "Job 40:22"}, "23": {"text": "Behold, he drinketh up a river, and hasteth not: he trusteth that he can draw up Jordan into his mouth.", "ref": "Job 40:23"}, "24": {"text": "He taketh it with his eyes: his nose pierceth through snares.", "ref": "Job 40:24"}}}, "41": {"chapter": "41", "title": "Job 41", "verses": {"1": {"text": "Canst thou draw out leviathan with an hook? or his tongue with a cord which thou lettest down?", "ref": "Job 41:1"}, "2": {"text": "Canst thou put an hook into his nose? or bore his jaw through with a thorn?", "ref": "Job 41:2"}, "3": {"text": "Will he make many supplications unto thee? will he speak soft words unto thee?", "ref": "Job 41:3"}, "4": {"text": "Will he make a covenant with thee? wilt thou take him for a servant for ever?", "ref": "Job 41:4"}, "5": {"text": "Wilt thou play with him as with a bird? or wilt thou bind him for thy maidens?", "ref": "Job 41:5"}, "6": {"text": "Shall the companions make a banquet of him? shall they part him among the merchants?", "ref": "Job 41:6"}, "7": {"text": "Canst thou fill his skin with barbed irons? or his head with fish spears?", "ref": "Job 41:7"}, "8": {"text": "Lay thine hand upon him, remember the battle, do no more.", "ref": "Job 41:8"}, "9": {"text": "Behold, the hope of him is in vain: shall not one be cast down even at the sight of him?", "ref": "Job 41:9"}, "10": {"text": "None is so fierce that dare stir him up: who then is able to stand before me?", "ref": "Job 41:10"}, "11": {"text": "Who hath prevented me, that I should repay him? whatsoever is under the whole heaven is mine.", "ref": "Job 41:11"}, "12": {"text": "I will not conceal his parts, nor his power, nor his comely proportion.", "ref": "Job 41:12"}, "13": {"text": "Who can discover the face of his garment? or who can come to him with his double bridle?", "ref": "Job 41:13"}, "14": {"text": "Who can open the doors of his face? his teeth are terrible round about.", "ref": "Job 41:14"}, "15": {"text": "His scales are his pride, shut up together as with a close seal.", "ref": "Job 41:15"}, "16": {"text": "One is so near to another, that no air can come between them.", "ref": "Job 41:16"}, "17": {"text": "They are joined one to another, they stick together, that they cannot be sundered.", "ref": "Job 41:17"}, "18": {"text": "By his neesings a light doth shine, and his eyes are like the eyelids of the morning.", "ref": "Job 41:18"}, "19": {"text": "Out of his mouth go burning lamps, and sparks of fire leap out.", "ref": "Job 41:19"}, "20": {"text": "Out of his nostrils goeth smoke, as out of a seething pot or caldron.", "ref": "Job 41:20"}, "21": {"text": "His breath kindleth coals, and a flame goeth out of his mouth.", "ref": "Job 41:21"}, "22": {"text": "In his neck remaineth strength, and sorrow is turned into joy before him.", "ref": "Job 41:22"}, "23": {"text": "The flakes of his flesh are joined together: they are firm in themselves; they cannot be moved.", "ref": "Job 41:23"}, "24": {"text": "His heart is as firm as a stone; yea, as hard as a piece of the nether millstone.", "ref": "Job 41:24"}, "25": {"text": "When he raiseth up himself, the mighty are afraid: by reason of breakings they purify themselves.", "ref": "Job 41:25"}, "26": {"text": "The sword of him that layeth at him cannot hold: the spear, the dart, nor the habergeon.", "ref": "Job 41:26"}, "27": {"text": "He esteemeth iron as straw, and brass as rotten wood.", "ref": "Job 41:27"}, "28": {"text": "The arrow cannot make him flee: slingstones are turned with him into stubble.", "ref": "Job 41:28"}, "29": {"text": "Darts are counted as stubble: he laugheth at the shaking of a spear.", "ref": "Job 41:29"}, "30": {"text": "Sharp stones are under him: he spreadeth sharp pointed things upon the mire.", "ref": "Job 41:30"}, "31": {"text": "He maketh the deep to boil like a pot: he maketh the sea like a pot of ointment.", "ref": "Job 41:31"}, "32": {"text": "He maketh a path to shine after him; one would think the deep to be hoary.", "ref": "Job 41:32"}, "33": {"text": "Upon earth there is not his like, who is made without fear.", "ref": "Job 41:33"}, "34": {"text": "He beholdeth all high things: he is a king over all the children of pride.", "ref": "Job 41:34"}}}, "42": {"chapter": "42", "title": "Job 42", "verses": {"1": {"text": "Then Job answered the LORD, and said,", "ref": "Job 42:1"}, "2": {"text": "I know that thou canst do every thing, and that no thought can be withholden from thee.", "ref": "Job 42:2"}, "3": {"text": "Who is he that hideth counsel without knowledge? therefore have I uttered that I understood not; things too wonderful for me, which I knew not.", "ref": "Job 42:3"}, "4": {"text": "Hear, I beseech thee, and I will speak: I will demand of thee, and declare thou unto me.", "ref": "Job 42:4"}, "5": {"text": "I have heard of thee by the hearing of the ear: but now mine eye seeth thee.", "ref": "Job 42:5"}, "6": {"text": "Wherefore I abhor myself, and repent in dust and ashes.", "ref": "Job 42:6"}, "7": {"text": "And it was so, that after the LORD had spoken these words unto Job, the LORD said to Eliphaz the Temanite, My wrath is kindled against thee, and against thy two friends: for ye have not spoken of me the thing that is right, as my servant Job hath.", "ref": "Job 42:7"}, "8": {"text": "Therefore take unto you now seven bullocks and seven rams, and go to my servant Job, and offer up for yourselves a burnt offering; and my servant Job shall pray for you: for him will I accept: lest I deal with you after your folly, in that ye have not spoken of me the thing which is right, like my servant Job.", "ref": "Job 42:8"}, "9": {"text": "So Eliphaz the Temanite and Bildad the Shuhite and Zophar the Naamathite went, and did according as the LORD commanded them: the LORD also accepted Job.", "ref": "Job 42:9"}, "10": {"text": "And the LORD turned the captivity of Job, when he prayed for his friends: also the LORD gave Job twice as much as he had before.", "ref": "Job 42:10"}, "11": {"text": "Then came there unto him all his brethren, and all his sisters, and all they that had been of his acquaintance before, and did eat bread with him in his house: and they bemoaned him, and comforted him over all the evil that the LORD had brought upon him: every man also gave him a piece of money, and every one an earring of gold.", "ref": "Job 42:11"}, "12": {"text": "So the LORD blessed the latter end of Job more than his beginning: for he had fourteen thousand sheep, and six thousand camels, and a thousand yoke of oxen, and a thousand she asses.", "ref": "Job 42:12"}, "13": {"text": "He had also seven sons and three daughters.", "ref": "Job 42:13"}, "14": {"text": "And he called the name of the first, Jemima; and the name of the second, Kezia; and the name of the third, Kerenhappuch.", "ref": "Job 42:14"}, "15": {"text": "And in all the land were no women found so fair as the daughters of Job: and their father gave them inheritance among their brethren.", "ref": "Job 42:15"}, "16": {"text": "After this lived Job an hundred and forty years, and saw his sons, and his sons’ sons, even four generations.", "ref": "Job 42:16"}, "17": {"text": "So Job died, being old and full of days.", "ref": "Job 42:17"}}}};
